export const ARTICLE_SERVER_RENDERED_PAYLOAD: Record<string, ArticleServerPayload> = {
  "deutsche-sprache-geschichte": {
    "content": "\n\n<!-- ════════════════════ HERO ════════════════════ -->\n<header class=\"hero\">\n  <p class=\"hero-eyebrow\">Sprachgeschichte · Von der Urzeit bis zur Gegenwart</p>\n  <h1>Die Geschichte<br>der <em>deutschen Sprache</em></h1>\n  <p class=\"hero-sub\">Von den indogermanischen Wurzeln über Althochdeutsch und Luthers Bibel bis zur modernen Standardsprache — eine Reise durch über 4000 Jahre Sprachentwicklung.</p>\n\n  <div class=\"era-strip\">\n    <span class=\"era-pill pill-indg\">Indogermanisch</span>\n    <span class=\"era-pill pill-germ\">Germanisch</span>\n    <span class=\"era-pill pill-ahd\">Althochdeutsch</span>\n    <span class=\"era-pill pill-mhd\">Mittelhochdeutsch</span>\n    <span class=\"era-pill pill-fnhd\">Frühneuhochdeutsch</span>\n    <span class=\"era-pill pill-nhd\">Neuhochdeutsch</span>\n    <span class=\"era-pill pill-mod\">Gegenwart</span>\n  </div>\n  <p class=\"era-sublabel\">ca. 2500 v. Chr. · bis heute</p>\n</header>\n\n<!-- ════════════════════ TIMELINE BAR ════════════════════ -->\n<div class=\"container\" style=\"max-width:880px; padding-bottom:0;\">\n  <div class=\"timeline-bar-wrap\">\n    <div class=\"timeline-bar\">\n      <div class=\"tb-seg tb-indg\"></div>\n      <div class=\"tb-seg tb-germ\"></div>\n      <div class=\"tb-seg tb-ahd\"></div>\n      <div class=\"tb-seg tb-mhd\"></div>\n      <div class=\"tb-seg tb-fnhd\"></div>\n      <div class=\"tb-seg tb-nhd\"></div>\n      <div class=\"tb-seg tb-mod\"></div>\n    </div>\n    <div class=\"timeline-labels\">\n      <span>~2500 v. Chr.</span>\n      <span>~500 v. Chr.</span>\n      <span>750 n. Chr.</span>\n      <span>1050</span>\n      <span>1350</span>\n      <span>1650</span>\n      <span>1900–heute</span>\n    </div>\n  </div>\n</div>\n\n<!-- ════════════════════ MAIN ════════════════════ -->\n<div class=\"container\">\n\n  <div class=\"section-header\"><h2>Sprachstufen im Detail</h2></div>\n\n  <!-- ─── INDOGERMANISCH ─── -->\n  <div class=\"era-card lv-indg\" id=\"era-indg\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-indg')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Urg.</span>\n        <span class=\"era-date\">~4000–500 v. Chr.</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Indogermanisch & Germanisch</p>\n        <p class=\"era-subtitle\">Die Wurzeln — lange vor dem Deutschen</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-indg\">\n        Das Deutsche gehört zur Sprachfamilie des <strong>Indogermanischen</strong> (auch Indoeuropäisch), einer rekonstruierten Protosprache, die vor mehreren Jahrtausenden auf dem eurasischen Kontinent gesprochen wurde. Aus dieser gemeinsamen Wurzel entwickelten sich im Laufe von Jahrtausenden zahlreiche Sprachzweige — darunter auch das <strong>Germanische</strong>, die direkte Vorfahrensprache des Deutschen. Das Indogermanische selbst ist nicht schriftlich überliefert; Linguisten haben es durch systematischen Vergleich verwandter Sprachen <em>rekonstruiert</em>. Wörter wie <em>*pṓds</em> (Fuß), <em>*mātér</em> (Mutter) oder <em>*nókʷts</em> (Nacht) lassen sich in Dutzenden europäischer und asiatischer Sprachen wiedererkennen.\n      </p>\n\n      <div class=\"fact-box\">\n        <strong>Was ist Sprachrekonstruktion?</strong> Sprachwissenschaftler erschließen die Ursprache durch das Vergleichende Methode (comparative method): Wenn viele nicht miteinander in Kontakt stehende Sprachen dasselbe Wort in ähnlicher Form kennen, lässt sich die ursprüngliche Form rückschließen. Das rekonstruierte Wort wird mit einem Sternchen (*) markiert.\n      </div>\n\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Indogermanische Sprachfamilien (Auswahl)</h4>\n          <ul>\n            <li><strong>Germanisch:</strong> Deutsch, Englisch, Niederländisch, Schwedisch, Norwegisch, Isländisch</li>\n            <li><strong>Romanisch:</strong> Latein → Französisch, Spanisch, Portugiesisch, Italienisch, Rumänisch</li>\n            <li><strong>Slawisch:</strong> Russisch, Polnisch, Ukrainisch, Tschechisch, Serbisch</li>\n            <li><strong>Indoiranisch:</strong> Sanskrit → Hindi, Urdu, Persisch</li>\n            <li><strong>Baltisch:</strong> Litauisch, Lettisch</li>\n            <li><strong>Griechisch, Keltisch, Albanisch, Armenisch</strong></li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Gemeinsame Wurzelwörter (Beispiele)</h4>\n          <ul>\n            <li><strong>Mutter:</strong> dt. <em>Mutter</em> · engl. <em>mother</em> · lat. <em>mater</em> · skr. <em>mātā</em></li>\n            <li><strong>Nacht:</strong> dt. <em>Nacht</em> · engl. <em>night</em> · lat. <em>nox</em> · griech. <em>nyx</em></li>\n            <li><strong>Drei:</strong> dt. <em>drei</em> · engl. <em>three</em> · lat. <em>tres</em> · russ. <em>tri</em></li>\n            <li><strong>Wasser:</strong> dt. <em>Wasser</em> · engl. <em>water</em> · russ. <em>voda</em></li>\n            <li><strong>Feuer:</strong> dt. <em>Feuer</em> · griech. <em>pyr</em> · engl. <em>fire</em></li>\n          </ul>\n        </div>\n        <div class=\"era-block card-block-full\">\n          <h4>Vom Germanischen zum Deutschen — drei Hauptzweige</h4>\n          <div class=\"feature-tags\">\n            <span class=\"feature-tag\">Nordgermanisch → Skandinavische Sprachen</span>\n            <span class=\"feature-tag\">Ostgermanisch → Gotisch (ausgestorben)</span>\n            <span class=\"feature-tag\">Westgermanisch → Deutsch, Englisch, Niederländisch, Friesisch</span>\n            <span class=\"feature-tag\">Urgermanisch ca. 500 v. Chr. – 200 n. Chr.</span>\n            <span class=\"feature-tag\">Erste Lautverschiebung (Grimmsches Gesetz) trennt Germanisch von anderen</span>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"family-grid\">\n        <div class=\"fg-cell\">\n          <div class=\"fg-icon\">🌍</div>\n          <div class=\"fg-label\">Nordgermanisch</div>\n          <div class=\"fg-langs\">Schwedisch, Dänisch,<br>Norwegisch, Isländisch,<br>Färöisch</div>\n        </div>\n        <div class=\"fg-cell\">\n          <div class=\"fg-icon\">📜</div>\n          <div class=\"fg-label\">Ostgermanisch</div>\n          <div class=\"fg-langs\">Gotisch (†), Vandalisch (†),<br>Burgundisch (†)<br><em>— heute ausgestorben —</em></div>\n        </div>\n        <div class=\"fg-cell\">\n          <div class=\"fg-icon\">🇩🇪</div>\n          <div class=\"fg-label\">Westgermanisch</div>\n          <div class=\"fg-langs\">Deutsch, Englisch,<br>Niederländisch, Friesisch,<br>Luxemburgisch, Jiddisch</div>\n        </div>\n      </div>\n\n    </div>\n  </div>\n\n  <!-- ─── ERSTE LAUTVERSCHIEBUNG / GRIMM ─── -->\n  <div class=\"era-card lv-germ\" id=\"era-germ\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-germ')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\" style=\"font-size:1.1rem;\">1. LS</span>\n        <span class=\"era-date\">~500 v. Chr.</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Die Erste Lautverschiebung</p>\n        <p class=\"era-subtitle\">Grimmsches Gesetz — Germanisch trennt sich vom Rest</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-germ\">\n        Bevor wir zum Deutschen selbst kommen, gibt es ein sprachhistorisches Schlüsselereignis zu verstehen: die <strong>Erste (Germanische) Lautverschiebung</strong>, auch <em>Grimmsches Gesetz</em> genannt (nach Jacob Grimm, der sie 1822 systematisch beschrieb). Diese Verschiebung fand ca. zwischen 500 v. Chr. und 200 n. Chr. statt und veränderte systematisch bestimmte Konsonanten — und zwar in allen germanischen Sprachen gleichzeitig. Das ist der Hauptgrund, warum englische und deutsche Wörter mit denselben lateinischen Wurzeln heute so verschieden aussehen.\n      </p>\n      <div class=\"era-grid\">\n        <div class=\"era-block era-block-full\">\n          <h4>Beispiele: Indogermanisch / Latein → Germanisch / Deutsch</h4>\n          <div class=\"laut-grid\">\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">p</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">f / ff</div>\n              <div class=\"laut-ex\">lat. <em>pater</em> → dt. <em>Vater</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">t</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">ð / d</div>\n              <div class=\"laut-ex\">lat. <em>tres</em> → engl. <em>three</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">k</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">h / x</div>\n              <div class=\"laut-ex\">lat. <em>canis</em> → engl. <em>hound</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">d</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">t</div>\n              <div class=\"laut-ex\">lat. <em>decem</em> → engl. <em>ten</em></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Was bedeutet das für uns heute?</h4>\n          <ul>\n            <li>Englisch und Deutsch klingen ähnlich, weil beide westgermanisch sind</li>\n            <li>Deutsch und Latein haben oft gleiche Wortwurzeln — aber verschiedene Laute</li>\n            <li>Jacob Grimm (1785–1863) beschrieb das Gesetz 1822 — derselbe Grimm, der Märchen sammelte</li>\n            <li>Das Gesetz gilt als Geburtsstunde der modernen Sprachwissenschaft</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Verwandtschaft: Deutsch ↔ Englisch ↔ Latein</h4>\n          <ul>\n            <li><em>Wasser</em> / <em>water</em> / lat. <em>aqua</em> — unterschiedliche Stämme</li>\n            <li><em>Fuß</em> / <em>foot</em> / lat. <em>pes/pedis</em> — alle verwandt</li>\n            <li><em>Herz</em> / <em>heart</em> / lat. <em>cor/cordis</em> — alle verwandt</li>\n            <li><em>Fisch</em> / <em>fish</em> / lat. <em>piscis</em> — p→f sichtbar</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── ZWEITE LAUTVERSCHIEBUNG ─── -->\n  <div class=\"era-card lv-ahd\" id=\"era-2ls\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-2ls')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\" style=\"font-size:1.1rem;\">2. LS</span>\n        <span class=\"era-date\">ca. 500–800 n. Chr.</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Die Zweite Lautverschiebung</p>\n        <p class=\"era-subtitle\">Hochdeutsch trennt sich von Niederländisch und Englisch</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-ahd\">\n        Die <strong>Zweite (Hochdeutsche) Lautverschiebung</strong> ist der wichtigste Einzelvorgang, der das Hochdeutsche (und damit das heutige Standarddeutsch) von den übrigen westgermanischen Sprachen — vor allem Englisch, Niederländisch und Niederdeutsch — trennt. Sie fand zwischen dem 5. und 8. Jahrhundert statt und betraf vor allem die Gebiete südlich der so genannten <strong>Benrather Linie</strong> (ungefähr auf Höhe von Düsseldorf/Aachen). Nördlich dieser Linie blieben die alten Formen erhalten — daraus entstanden Niederdeutsch und Niederländisch. Südlich davon wurden die Konsonanten systematisch verschoben.\n      </p>\n\n      <div class=\"fact-box\">\n        <strong>Die Benrather Linie</strong> ist eine isoglosse (Sprachgrenzlinie), die ungefähr durch Düsseldorf/Benrath verläuft. Nördlich: <em>ik make</em> (Niederdeutsch). Südlich: <em>ich mache</em> (Hochdeutsch). Diese Linie ist bis heute in deutschen Dialekten spürbar.\n      </div>\n\n      <div class=\"era-grid\">\n        <div class=\"era-block era-block-full\">\n          <h4>Die wichtigsten Lautveränderungen — mit Beispielen</h4>\n          <div class=\"laut-grid\">\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">p</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">pf / ff</div>\n              <div class=\"laut-ex\">engl. <em>pepper</em> → dt. <em>Pfeffer</em><br>engl. <em>open</em> → dt. <em>offen</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">t</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">z / ss / ß</div>\n              <div class=\"laut-ex\">engl. <em>ten</em> → dt. <em>zehn</em><br>engl. <em>water</em> → dt. <em>Wasser</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">d</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">t</div>\n              <div class=\"laut-ex\">engl. <em>day</em> → dt. <em>Tag</em><br>engl. <em>door</em> → dt. <em>Tür</em></div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\">k</div>\n              <div class=\"laut-arrow\">↓</div>\n              <div class=\"laut-to\">ch / ck</div>\n              <div class=\"laut-ex\">engl. <em>make</em> → dt. <em>machen</em><br>engl. <em>book</em> → dt. <em>Buch</em></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Warum fand die Verschiebung nur im Süden statt?</h4>\n          <ul>\n            <li>Vermutlich Einfluss aus dem romanisch-sprachigen Alpenraum</li>\n            <li>Intensive Kontakte mit der romanischen Bevölkerung Norditaliens und Rätiens</li>\n            <li>Geographische Isolation begünstigte eigenständige Entwicklungen</li>\n            <li>Die genaue Ursache ist bis heute wissenschaftlich nicht endgültig geklärt</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Auswirkungen bis heute</h4>\n          <ul>\n            <li>Niederländisch und Englisch haben die Verschiebung <em>nicht</em> mitgemacht</li>\n            <li>„Hochdeutsch\" bedeutet ursprünglich „Sprache der Hochlande (Süden)\" — nicht „vornehm\"</li>\n            <li>Die heutigen deutschen Dialekte spiegeln noch immer diese historische Grenzlinie wider</li>\n            <li>Das ist der Hauptgrund für das unterschiedliche Aussehen dt./engl. Wörter bei gleicher Wurzel</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── ALTHOCHDEUTSCH ─── -->\n  <div class=\"era-card lv-ahd\" id=\"era-ahd\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-ahd')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Ahd.</span>\n        <span class=\"era-date\">ca. 750–1050</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Althochdeutsch</p>\n        <p class=\"era-subtitle\">„Die ersten großen Texte\" — Deutsch im karolingischen Zeitalter</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-ahd\">\n        Als <strong>Althochdeutsch</strong> bezeichnet man die älteste Stufe des Deutschen, die in schriftlichen Quellen fassbar ist — grob zwischen 750 und 1050 n. Chr. Diese Periode entspricht dem Zeitalter Karls des Großen und der karolingischen Renaissance. Die Sprache war noch kein einheitliches System: Es gab eine Vielzahl regionaler Schreibtraditionen und Dialekte (Bairisch, Alemannisch, Fränkisch). Gemeinsam ist ihnen, dass sie die Auswirkungen der Zweiten Lautverschiebung zeigen und damit klar als „hochdeutsch\" erkennbar sind. Das meiste schriftliche Material stammt aus kirchlichen und klösterlichen Kontexten — Latein war weiterhin die dominante Schriftsprache.\n      </p>\n\n      <div class=\"notice\">\n        <strong>⚠️ Wichtiger Hinweis:</strong> Althochdeutsch ist für heutige Leser praktisch <em>unverständlich</em> — es ist kein „altes Deutsch mit seltsamer Rechtschreibung\", sondern eine eigenständige Sprachstufe, die sich in Grammatik, Wortschatz und Lautstand grundlegend vom heutigen Deutsch unterscheidet.\n      </div>\n\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Merkmale der Sprache</h4>\n          <ul>\n            <li>Reiches Kasussystem mit vier Fällen (wie heute) plus Instrumental</li>\n            <li>Sehr stark flektierende Sprache — viele Endungen und Formen</li>\n            <li>Kein einheitlicher Standard: regionale Dialekte bestimmen die Schrift</li>\n            <li>Starke Präsenz des Lateins als Bildungssprache neben dem Deutschen</li>\n            <li>Viele Lehnwörter aus dem Lateinischen und vereinzelt aus dem Griechischen</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Wichtige Texte und Quellen</h4>\n          <ul>\n            <li><strong>Hildebrandslied</strong> (ca. 830) — ältestes Zeugnis weltlicher Heldendichtung in dt. Sprache</li>\n            <li><strong>Mersebur­ger Zaubersprüche</strong> (10. Jh.) — heidnische Spruchdichtung</li>\n            <li><strong>Tatian</strong> (ca. 830) — ahd. Übersetzung eines Evangelienharmoniums</li>\n            <li><strong>Notker von St. Gallen</strong> (gest. 1022) — bedeutender Übersetzer phil. Texte ins Althochdeutsche</li>\n            <li>Otfrids <strong>Evangelienbuch</strong> (ca. 863–871) — erstes bekanntes Reimgedicht auf Dt.</li>\n          </ul>\n        </div>\n        <div class=\"era-block era-block-full\">\n          <h4>Sprachvergleich: Althochdeutsch → Neuhochdeutsch</h4>\n          <div class=\"text-example lv-ahd\">\n            <div class=\"original\">„Ik gihorta dat seggen, dat sih urhettun ænon muotin, Hiltibrant enti Hadubrant untar heriun tuem.\"</div>\n            <div class=\"translation\">„Ich hörte das sagen, dass sich zwei Einzelkämpfer trafen, Hildebrand und Hadubrand, zwischen zwei Heeren.\"</div>\n            <div class=\"source\">HILDEBRANDSLIED · ca. 830 n. Chr. · Kloster Fulda</div>\n          </div>\n          <div class=\"text-example lv-ahd\">\n            <div class=\"original\">„In gotes namen faro ih, gotes geleit ih habe. Nu wil ih mih beuuergen, thaz mih nioman kiruoche.\"</div>\n            <div class=\"translation\">„In Gottes Namen fahre ich, Gottes Geleit habe ich. Nun will ich mich schützen, dass mich niemand angreife.\"</div>\n            <div class=\"source\">WEISSENBUR­GER KATECHISMUS · ca. 790 n. Chr.</div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Historischer Kontext</h4>\n          <ul>\n            <li>Karl der Große (reg. 768–814) fördert Schriftlichkeit und Bildung</li>\n            <li>Klöster (Fulda, St. Gallen, Reichenau) sind Zentren der Schriftkultur</li>\n            <li>Missionierung germanischer Stämme verbreitet den Schriftgebrauch</li>\n            <li>Latein dominiert Verwaltung, Kirche, Wissenschaft</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Merksatz für die Schule</h4>\n          <ul>\n            <li>Althochdeutsch ≠ modernes Deutsch — fast eine Fremdsprache für uns</li>\n            <li>Kein Standard, viele Dialekte, viel Latein daneben</li>\n            <li>Schreiben noch eine Seltenheit — gehörte zu Klerus und Gelehrten</li>\n            <li>Zweite Lautverschiebung ist bereits vollzogen und sichtbar</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── MITTELHOCHDEUTSCH ─── -->\n  <div class=\"era-card lv-mhd\" id=\"era-mhd\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-mhd')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Mhd.</span>\n        <span class=\"era-date\">ca. 1050–1350</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Mittelhochdeutsch</p>\n        <p class=\"era-subtitle\">„Ritter, Minnesang und Blütezeit der Literatur\"</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-mhd\">\n        Das <strong>Mittelhochdeutsche</strong> ist die Sprache der höfischen Ritterkultur und des Stauferzeitzeitalters (12./13. Jahrhundert). Es ist die erste Sprachstufe, bei der sich eine gewisse überregionale literarische Schreibtradition herausbildet — ausgelöst durch die Blüte der <em>höfischen Epik</em> und des <em>Minnesangs</em>. Der bekannteste Text der Epoche ist das Nibelungenlied. Im Vergleich zum Althochdeutschen hat das Mittelhochdeutsche bereits stärker reduzierte Endungen, die Sprache klingt dadurch etwas „leichter\". Dennoch: Ein einheitlicher Schriftstandard existiert noch immer nicht.\n      </p>\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Merkmale der Sprache</h4>\n          <ul>\n            <li>Abschwächung der vollen Endvokale zu Schwa (ə): <em>-a, -o, -u</em> → <em>-e</em></li>\n            <li>Beginn des Umlauts als grammatisches Mittel (Plural-Bildung)</li>\n            <li>Stärkere Annäherung der regionalen Schreibsprachen in der höfischen Literatur</li>\n            <li>Kein einheitlicher Standard — immer noch dialektbasiert</li>\n            <li>Viele Lehnwörter aus dem Altfranzösischen (Ritterkultur): <em>Turnier, Palast, Preis</em></li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Bedeutende Texte und Autoren</h4>\n          <ul>\n            <li><strong>Nibelungenlied</strong> (ca. 1200) — nationales Heldenepos, Siegfried und Brünhild</li>\n            <li><strong>Wolfram von Eschenbach</strong> — <em>Parzival</em> (ca. 1200–1210)</li>\n            <li><strong>Hartmann von Aue</strong> — <em>Erec</em>, <em>Iwein</em></li>\n            <li><strong>Walther von der Vogelweide</strong> (ca. 1170–1230) — bedeutendster Minnesänger</li>\n            <li><strong>Gottfried von Straßburg</strong> — <em>Tristan</em> (ca. 1210)</li>\n          </ul>\n        </div>\n        <div class=\"era-block era-block-full\">\n          <h4>Sprachbeispiele: Mittelhochdeutsch → Neuhochdeutsch</h4>\n          <div class=\"text-example lv-mhd\">\n            <div class=\"original\">„Uns ist in alten mæren wunders vil geseit von helden lobebæren, von grôzer arebeit…\"</div>\n            <div class=\"translation\">„Uns wird in alten Erzählungen Wunderbares viel berichtet von rühmlichen Helden, von großer Mühsal…\"</div>\n            <div class=\"source\">NIBELUNGENLIED · Erste Strophe · ca. 1200 n. Chr.</div>\n          </div>\n          <div class=\"text-example lv-mhd\">\n            <div class=\"original\">„Under der linden an der heide, dâ unser zweier bette was, dâ mugt ir vinden schône beide gebrochen bluomen unde gras.\"</div>\n            <div class=\"translation\">„Unter der Linde auf der Heide, wo unser beider Lager war, da könnt ihr schön beide finden: zerbrochene Blumen und Gras.\"</div>\n            <div class=\"source\">WALTHER VON DER VOGELWEIDE · Lied L.39,11 · ca. 1200</div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Historischer Kontext</h4>\n          <ul>\n            <li>Staufische Kaiser (Friedrich I. Barbarossa, Friedrich II.) fördern Kultur und Literatur</li>\n            <li>Kreuzzüge bringen Kontakte mit arabischer, byzantinischer Kultur</li>\n            <li>Städtewachstum beginnt — Bürgertum entsteht</li>\n            <li>Pest (1347–1351) beendet die mittelhochdeutsche Blütezeit</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Lehnwörter aus dem Altfranzösischen</h4>\n          <div class=\"feature-tags\">\n            <span class=\"feature-tag\">Turnier ← fr. tournoi</span>\n            <span class=\"feature-tag\">Palast ← fr. palais</span>\n            <span class=\"feature-tag\">Preis ← fr. prix</span>\n            <span class=\"feature-tag\">Abenteuer ← fr. aventure</span>\n            <span class=\"feature-tag\">Tanz ← fr. danse</span>\n            <span class=\"feature-tag\">Bastei ← fr. bastion</span>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── FRÜHNEUHOCHDEUTSCH ─── -->\n  <div class=\"era-card lv-fnhd\" id=\"era-fnhd\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-fnhd')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Frnhd.</span>\n        <span class=\"era-date\">ca. 1350–1650</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Frühneuhochdeutsch</p>\n        <p class=\"era-subtitle\">„Der Weg zur gemeinsamen Schriftsprache\" — Buchdruck und Luther</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-fnhd\">\n        Das <strong>Frühneuhochdeutsche</strong> ist die entscheidende Übergangsphase in der Geschichte der deutschen Sprache. In dieser Zeit — grob zwischen 1350 und 1650 — entwickelt sich erstmals eine überregionale deutsche <em>Schriftsprache</em>, die über einzelne Dialekte hinausreicht. Treibende Kräfte sind: das Wachstum der Städte, der Aufschwung von Handel und Verwaltung, die Entstehung sogenannter <strong>Kanzleisprachen</strong>, die Erfindung des Buchdrucks durch Johannes Gutenberg (um 1450) und schließlich Luthers Bibelübersetzung (Neues Testament 1522, Vollbibel 1534). Diese Epoche schafft die Grundlagen für das heutige Standarddeutsch.\n      </p>\n\n      <div class=\"notice\">\n        <strong>⚠️ Häufiges Missverständnis über Luther:</strong> Martin Luther hat die deutsche Sprache <em>nicht erfunden</em> und auch nicht allein geschaffen. Er hat eine bereits vorhandene überregionale Schreibtradition aufgegriffen, gepflegt und durch die massenhafte Verbreitung seiner Texte — dank des Buchdrucks — enorm populär gemacht. Der Einfluss war real und bedeutend, aber er war Teil einer längeren Entwicklung, nicht deren Anfang.\n      </div>\n\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Die drei großen Kräfte dieser Epoche</h4>\n          <ul>\n            <li><strong>Kanzleisprachen:</strong> Verwaltungssprachen der Fürstentümer und Städte streben nach Überregionalität — besonders die <em>Kaiserliche Kanzlei</em> unter Maximilian I. und die <em>Sächsische Kanzlei</em> gelten als besonders einflussreich</li>\n            <li><strong>Buchdruck (ca. 1450):</strong> Johannes Gutenberg ermöglicht massenhafte Textverbreitung — eine einheitlichere Schreibweise wird praktisch notwendig</li>\n            <li><strong>Luthers Übersetzung (1522/1534):</strong> Enorm weit verbreitet, von vielen Menschen gelesen — stabilisiert bestimmte Formen und Wendungen</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Sprachliche Veränderungen</h4>\n          <ul>\n            <li>Entstehung der <em>neuhochdeutschen Diphthongierung</em>: mhd. <em>mîn</em> → nhd. <em>mein</em></li>\n            <li>Entstehung der <em>neuhochdeutschen Monophthongierung</em>: mhd. <em>guot</em> → nhd. <em>gut</em></li>\n            <li>Vereinheitlichung der Schreibweisen nimmt zu</li>\n            <li>Wortschatz expandiert durch Humanismus und Wissenschaft</li>\n            <li>Erste Grammatiken des Deutschen (Fabian Frangk, 1531)</li>\n          </ul>\n        </div>\n        <div class=\"era-block era-block-full\">\n          <h4>Sprachbeispiele: Frühneuhochdeutsch → Neuhochdeutsch</h4>\n          <div class=\"text-example lv-fnhd\">\n            <div class=\"original\">„Am anfang schuff Gott Himel und Erden. Und die Erde war wüst und leer, und es war finster auff der Tieffe…\"</div>\n            <div class=\"translation\">„Am Anfang schuf Gott Himmel und Erde. Und die Erde war wüst und leer, und es war finster auf der Tiefe…\" — bereits für heutige Leser gut verständlich!</div>\n            <div class=\"source\">MARTIN LUTHER · Bibelübersetzung (Genesis 1,1–2) · 1534</div>\n          </div>\n          <div class=\"text-example lv-fnhd\">\n            <div class=\"original\">„Ich hab die gemeyne Man auff dem marckt, die Mutter im haus, die Kinder auff der gassen angesehen und denselbigen auff das Maul geschaut…\"</div>\n            <div class=\"translation\">„Ich habe den gemeinen Mann auf dem Markt, die Mutter im Haus, die Kinder auf der Gasse angeschaut und denselben auf den Mund geschaut…\"</div>\n            <div class=\"source\">MARTIN LUTHER · Sendbrief vom Dolmetschen · 1530</div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Luthers eigene Worte zum Übersetzen</h4>\n          <ul>\n            <li>Luther schrieb 1530: Er wolle „dem Volk aufs Maul schauen\" — also die Volkssprache nutzen</li>\n            <li>Er orientierte sich bewusst an der gesprochenen Sprache der einfachen Leute</li>\n            <li>Seine Bibelübersetzung prägte Hunderte von Wörtern und Phrasen, die wir heute noch kennen</li>\n            <li>Begriffe wie <em>Lückenbüßer, Lästermaul, im Dunkeln tappen</em> gehen auf Luther zurück</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Historischer Kontext</h4>\n          <ul>\n            <li>Humanismus und Renaissance erreichen Deutschland</li>\n            <li>Reformation (ab 1517) — Religion als Massenthema, Sprache als Medium</li>\n            <li>Dreißigjähriger Krieg (1618–1648) — Einfluss von Fremdwörtern, besonders Französisch</li>\n            <li>Erste Sprachgesellschaften entstehen (Fruchtbringende Gesellschaft, 1617)</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── NEUHOCHDEUTSCH ─── -->\n  <div class=\"era-card lv-nhd\" id=\"era-nhd\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-nhd')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Nhd.</span>\n        <span class=\"era-date\">ca. 1650–1900</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Neuhochdeutsch</p>\n        <p class=\"era-subtitle\">„Standardisierung und Normierung\" — Grammatiken, Wörterbücher, Schulsprache</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-nhd\">\n        Ab ca. 1650 spricht man von <strong>Neuhochdeutsch</strong>: Die Grundstruktur der Sprache ist dem heutigen Deutsch sehr ähnlich, ein Muttersprachler kann Texte aus dieser Zeit ohne größere Probleme lesen. Die entscheidende Entwicklung dieser Phase ist die <strong>Normierung</strong>: Grammatiker, Sprachpfleger und schließlich staatliche Institutionen arbeiten daran, Rechtschreibung, Grammatik und Wortschatz zu vereinheitlichen. Die deutsche Klassik (Goethe, Schiller) prägt das Bild der Hochsprache, die Sprachwissenschaft entsteht als eigenständige Disziplin, und im 19. Jahrhundert werden die ersten verbindlichen Rechtschreibregeln eingeführt.\n      </p>\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Wichtige Meilensteine</h4>\n          <ul>\n            <li><strong>1663:</strong> Justus Georg Schottelius — <em>Ausführliche Arbeit von der teutschen HaubtSprache</em>, erste systematische Grammatik</li>\n            <li><strong>1748:</strong> Johann Christoph Gottsched — normative Grammatik des Hochdeutschen</li>\n            <li><strong>1774–1810:</strong> Johann Wolfgang von Goethe und Friedrich Schiller prägen Stil und Wortschatz der Hochsprache</li>\n            <li><strong>1852–1961:</strong> Jacob und Wilhelm Grimm beginnen das <em>Deutsche Wörterbuch</em> — das größte historische Wörterbuch der deutschen Sprache (erst 1961 fertiggestellt)</li>\n            <li><strong>1880:</strong> Konrad Duden — <em>Vollständiges Orthographisches Wörterbuch der deutschen Sprache</em></li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Die Brüder Grimm — mehr als Märchen</h4>\n          <ul>\n            <li>Jacob Grimm (1785–1863) und Wilhelm Grimm (1786–1859) sind zuerst Sprachwissenschaftler</li>\n            <li>Jacob Grimms <em>Deutsche Grammatik</em> (1819–1837) ist ein Grundlagenwerk der Germanistik</li>\n            <li>Das <em>Deutsche Wörterbuch</em> (DWB) dokumentiert erstmals historisch den deutschen Wortschatz</li>\n            <li>Die Märchensammlungen sind ein Nebenprodukt ihrer sprachhistorischen Forschung</li>\n            <li>Jacob Grimm beschrieb auch das Grimm'sche Gesetz (Erste Lautverschiebung)</li>\n          </ul>\n        </div>\n        <div class=\"era-block era-block-full\">\n          <h4>Sprachbeispiele: Neuhochdeutsch (17.–19. Jh.)</h4>\n          <div class=\"text-example lv-nhd\">\n            <div class=\"original\">„Zwei Seelen wohnen, ach! in meiner Brust, die eine will sich von der andern trennen; die eine hält, in derber Liebeslust, sich an die Welt mit klammernden Organen…\"</div>\n            <div class=\"translation\">Für heutige Leser problemlos verständlich — die Sprache ist im Wesentlichen modern.</div>\n            <div class=\"source\">JOHANN WOLFGANG VON GOETHE · Faust I, 1112–1115 · 1808</div>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Sprachpflege und Purismus</h4>\n          <ul>\n            <li>Im 17./18. Jh. starke Gegenbewegung zu Fremdwörtern (bes. Französisch)</li>\n            <li>Fruchtbringende Gesellschaft (1617) — erste dt. Sprachgesellschaft zur Sprachpflege</li>\n            <li>Joachim Heinrich Campe ersetzt Fremdwörter: <em>Zeitung</em> statt <em>Journal</em>, <em>Briefwechsel</em> statt <em>Korrespondenz</em></li>\n            <li>Viele dieser Ersatzwörter haben sich durchgesetzt und sind heute selbstverständlich</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Neue Wörter durch Geschichte</h4>\n          <div class=\"feature-tags\">\n            <span class=\"feature-tag\">Demokratie (Griech.)</span>\n            <span class=\"feature-tag\">Lokomotive (Lat./Engl.)</span>\n            <span class=\"feature-tag\">Elektrizität (Griech.)</span>\n            <span class=\"feature-tag\">Nation (Lat.)</span>\n            <span class=\"feature-tag\">Revolution (Lat.)</span>\n            <span class=\"feature-tag\">Industrie (Lat.)</span>\n            <span class=\"feature-tag\">Zeitung (dt. Neuschöpfung)</span>\n            <span class=\"feature-tag\">Briefwechsel (dt. Neuschöpfung)</span>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── MODERNE ─── -->\n  <div class=\"era-card lv-mod\" id=\"era-mod\">\n    <div class=\"era-card-header\" onclick=\"toggleEra('era-mod')\">\n      <div class=\"era-year-block\">\n        <span class=\"era-abbr\">Mod.</span>\n        <span class=\"era-date\">1900–heute</span>\n      </div>\n      <div>\n        <p class=\"era-title\">Modernes Deutsch</p>\n        <p class=\"era-subtitle\">„Normen, Wandel und Globalisierung\" — von der Rechtschreibreform bis zum Internet</p>\n      </div>\n      <div class=\"era-toggle\">▾</div>\n    </div>\n    <div class=\"era-body\">\n      <p class=\"era-description lv-mod\">\n        Das <strong>heutige Standarddeutsch</strong> ist das Ergebnis aller vorangegangenen Entwicklungen — geformt durch Jahrhunderte Lautwandel, Normierung und kulturellen Austausch. Es ist eine plurizentrische Sprache: Es gibt <strong>drei anerkannte Standardvarietäten</strong> — Deutsch in Deutschland (D), Österreich (A) und der Schweiz (CH) — die sich in Wortschatz, Aussprache und teilweise auch Grammatik leicht unterscheiden. Die Sprache ist lebendig: Neue Wörter kommen ständig hinzu, Schreibnormen werden debattiert und angepasst, und das Digitale verändert die Kommunikationsweise tiefgreifend.\n      </p>\n      <div class=\"era-grid\">\n        <div class=\"era-block\">\n          <h4>Rechtschreibreform 1996</h4>\n          <ul>\n            <li>Beschlossen von Deutschland, Österreich und der Schweiz gemeinsam</li>\n            <li>Vereinfachung der ss/ß-Regel: nach kurzem Vokal <em>ss</em>, nach langem <em>ß</em> (Straße, aber Fluss)</li>\n            <li>Getrennt-/Zusammenschreibung und Groß-/Kleinschreibung teilweise neu geregelt</li>\n            <li>Umstrittene Reform — viele Verlage, Redaktionen und Personen lehnten sie zunächst ab</li>\n            <li>Seit 2006 verbindlich für Schulen und Behörden in allen drei Ländern</li>\n            <li>Hüter der Norm: <strong>Rat für deutsche Rechtschreibung</strong> (gegründet 2004)</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Deutsch als plurizentrische Sprache</h4>\n          <ul>\n            <li><strong>D-Deutsch:</strong> Standardreferenz für Grammatik und Aussprache</li>\n            <li><strong>Österreichisches Deutsch:</strong> eigenes Standardwörterbuch (ÖWB), viele österreichische Standardausdrücke (<em>Jänner</em> statt <em>Januar</em>, <em>heuer</em> statt <em>dieses Jahr</em>)</li>\n            <li><strong>Schweizer Standarddeutsch:</strong> kein ß (nur ss), eigene Ausdrücke (<em>Velo</em> statt <em>Fahrrad</em>), Einfluss des Französischen</li>\n            <li>Alle drei Varietäten gelten als gleichwertig korrekt</li>\n          </ul>\n        </div>\n        <div class=\"era-block\">\n          <h4>Neue Wörter im 20./21. Jahrhundert</h4>\n          <div class=\"feature-tags\">\n            <span class=\"feature-tag\">Handy (engl. Ursprung, dt. Bedeutung)</span>\n            <span class=\"feature-tag\">googeln (Verb vom Markennamen)</span>\n            <span class=\"feature-tag\">liken, posten, streamen</span>\n            <span class=\"feature-tag\">Homeoffice, Lockdown</span>\n            <span class=\"feature-tag\">Nachhaltigkeit (dt. Aufwertung)</span>\n            <span class=\"feature-tag\">Klimawandel (Neuprägun)</span>\n            <span class=\"feature-tag\">Gendern (neue Bedeutung)</span>\n            <span class=\"feature-tag\">Corona-Wortschatz: Impfgipfel, Inzidenz</span>\n          </div>\n        </div>\n        <div class=\"era-block\">\n          <h4>Aktuelle Themen und Debatten</h4>\n          <ul>\n            <li><strong>Gendern:</strong> Verwendung gendergerechter Sprache (Lehrer*innen, Lehrkräfte, das Lehrende) — gesellschaftlich intensiv diskutiert</li>\n            <li><strong>Anglizismen:</strong> Englische Lehnwörter fluten den Alltag — Einige werden integriert, andere verdrängen dt. Wörter</li>\n            <li><strong>Sprachverfall?</strong> Jugendsprache und Chatsprache werden oft als „Verfall\" wahrgenommen — Linguisten sehen es als natürlichen Wandel</li>\n            <li><strong>Einfache Sprache:</strong> Wachsendes Bewusstsein für barrierefreie Kommunikation</li>\n          </ul>\n        </div>\n        <div class=\"era-block era-block-full\">\n          <h4>Deutsch in Zahlen heute</h4>\n          <div class=\"laut-grid\" style=\"grid-template-columns: repeat(4,1fr);\">\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\" style=\"color:var(--mod); font-size:1.5rem;\">~100 Mio.</div>\n              <div class=\"laut-ex\" style=\"margin-top:6px;\">Muttersprachler weltweit</div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\" style=\"color:var(--mod); font-size:1.5rem;\">~80 Mio.</div>\n              <div class=\"laut-ex\" style=\"margin-top:6px;\">Lernende weltweit (DaF/DaZ)</div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\" style=\"color:var(--mod); font-size:1.5rem;\">3</div>\n              <div class=\"laut-ex\" style=\"margin-top:6px;\">offizielle Standardvarietäten (DE/AT/CH)</div>\n            </div>\n            <div class=\"laut-cell\">\n              <div class=\"laut-from\" style=\"color:var(--mod); font-size:1.5rem;\">5,3 Mio.</div>\n              <div class=\"laut-ex\" style=\"margin-top:6px;\">Einträge im Deutschen Wörterbuch (DWB)</div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ VERGLEICHSTABELLE ════════════════════ -->\n  <div class=\"section-header\"><h2>Sprachstufen im Vergleich</h2></div>\n\n  <p style=\"color:var(--muted); margin-bottom:20px; font-size:0.95rem; line-height:1.75;\">\n    So entwickelte sich dasselbe Wort über die Jahrhunderte — gut zu sehen: Wortschatz und Lautstand ändern sich, aber Kern-Wörter bleiben erkennbar verwandt.\n  </p>\n\n  <table class=\"compare-table\">\n    <thead>\n      <tr>\n        <th>Sprachstufe</th>\n        <th>„machen\"</th>\n        <th>„ich\"</th>\n        <th>„Tag\"</th>\n        <th>„gut\"</th>\n        <th>„Haus\"</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td style=\"color:var(--germ)\">Germanisch</td>\n        <td><em>*makōną</em></td>\n        <td><em>*ek</em></td>\n        <td><em>*dagaz</em></td>\n        <td><em>*gōdaz</em></td>\n        <td><em>*hūsą</em></td>\n      </tr>\n      <tr>\n        <td style=\"color:var(--ahd)\">Althochdeutsch</td>\n        <td><em>mahhōn</em></td>\n        <td><em>ih</em></td>\n        <td><em>tag</em></td>\n        <td><em>guot</em></td>\n        <td><em>hūs</em></td>\n      </tr>\n      <tr>\n        <td style=\"color:var(--mhd)\">Mittelhochdeutsch</td>\n        <td><em>machen</em></td>\n        <td><em>ich</em></td>\n        <td><em>tac</em></td>\n        <td><em>guot</em></td>\n        <td><em>hûs</em></td>\n      </tr>\n      <tr>\n        <td style=\"color:var(--fnhd)\">Frühneuhochdeutsch</td>\n        <td><em>machen</em></td>\n        <td><em>ich</em></td>\n        <td><em>Tag</em></td>\n        <td><em>gut</em></td>\n        <td><em>Haus</em></td>\n      </tr>\n      <tr>\n        <td style=\"color:var(--nhd)\">Neuhochdeutsch</td>\n        <td><strong>machen</strong></td>\n        <td><strong>ich</strong></td>\n        <td><strong>Tag</strong></td>\n        <td><strong>gut</strong></td>\n        <td><strong>Haus</strong></td>\n      </tr>\n      <tr>\n        <td>Englisch (Vgl.)</td>\n        <td><em>make</em></td>\n        <td><em>I</em></td>\n        <td><em>day</em></td>\n        <td><em>good</em></td>\n        <td><em>house</em></td>\n      </tr>\n      <tr>\n        <td>Niederländisch (Vgl.)</td>\n        <td><em>maken</em></td>\n        <td><em>ik</em></td>\n        <td><em>dag</em></td>\n        <td><em>goed</em></td>\n        <td><em>huis</em></td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- ════════════════════ SCHLÜSSEL-TAKEAWAYS ════════════════════ -->\n  <div class=\"section-header\"><h2>Das Wichtigste im Überblick</h2></div>\n\n  <div class=\"keyfact-grid\">\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🌱</div>\n      <div class=\"keyfact-title\">Deutsch ist schrittweise gewachsen</div>\n      <div class=\"keyfact-desc\">Die Sprache ist nicht plötzlich entstanden, sondern über viele Jahrhunderte in Stufen gewachsen — von indogermanischen Wurzeln über germanische Dialekte bis zur modernen Standardsprache.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🔄</div>\n      <div class=\"keyfact-title\">Zwei Lautverschiebungen sind entscheidend</div>\n      <div class=\"keyfact-desc\">Die Erste Lautverschiebung (Grimmsches Gesetz) trennte Germanisch vom Rest der indogermanischen Familie. Die Zweite trennte Hochdeutsch von Englisch und Niederländisch.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">📜</div>\n      <div class=\"keyfact-title\">Luther hat Deutsch nicht erfunden</div>\n      <div class=\"keyfact-desc\">Luther hat eine bereits vorhandene überregionale Schreibtradition durch die Massenverbreitung seiner Bibelübersetzung enorm gestärkt — aber nicht aus dem Nichts erschaffen.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🖨️</div>\n      <div class=\"keyfact-title\">Buchdruck als Turbo der Vereinheitlichung</div>\n      <div class=\"keyfact-desc\">Gutenbergs Buchdruck (ca. 1450) machte eine einheitlichere Schreibweise praktisch notwendig — und ermöglichte die massenhafte Verbreitung von Luthers Texten.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">📖</div>\n      <div class=\"keyfact-title\">Normierung im 19. Jahrhundert</div>\n      <div class=\"keyfact-desc\">Erst im 19. Jahrhundert wurden verbindliche Rechtschreibregeln eingeführt. Konrad Dudens Wörterbuch (1880) und die Brüder Grimm prägten die Standardisierung entscheidend.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🌍</div>\n      <div class=\"keyfact-title\">Deutsch lebt und verändert sich weiter</div>\n      <div class=\"keyfact-desc\">Wortschatz, Aussprache und Schreibnormen entwickeln sich weiter — durch Technologie, Globalisierung, Migration und gesellschaftlichen Wandel. Sprachverfall? Nein — Sprachwandel.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🇦🇹</div>\n      <div class=\"keyfact-title\">Drei gleichwertige Standardvarietäten</div>\n      <div class=\"keyfact-desc\">Deutsch in Deutschland, Österreich und der Schweiz sind drei gleichberechtigte Standardsprachen — keine ist „richtiger\" als die anderen. Das nennt man Plurizentrizität.</div>\n    </div>\n    <div class=\"keyfact-card\">\n      <div class=\"keyfact-icon\">🔗</div>\n      <div class=\"keyfact-title\">Verwandtschaft mit vielen Sprachen</div>\n      <div class=\"keyfact-desc\">Wer Deutsch kennt, erkennt Strukturen in Englisch, Niederländisch, Schwedisch und sogar in Griechisch oder Latein — denn alle teilen die gemeinsame indogermanische Wurzel.</div>\n    </div>\n  </div>\n\n</div>\n\n<!-- ════════════════════ FOOTER ════════════════════ -->\n<footer>\n  <p>Quellen und weiterführende Literatur: <a href=\"https://www.ids-mannheim.de\" target=\"_blank\">Institut für Deutsche Sprache (IDS) Mannheim</a> · <a href=\"https://www.dwds.de\" target=\"_blank\">Digitales Wörterbuch der deutschen Sprache (DWDS)</a> · <a href=\"https://www.goethe.de\" target=\"_blank\">Goethe-Institut</a></p>\n  <p style=\"margin-top:6px;\">Peter von Polenz: <em>Deutsche Sprachgeschichte</em> (de Gruyter) · Wilhelm Schmidt: <em>Geschichte der deutschen Sprache</em> (Hirzel)</p>\n  <p style=\"margin-top:6px;\">Artikel erstellt 2025 · Für Unterrichtszwecke</p>\n</footer>\n\n<script>\n  function toggleEra(id) {\n    const card = document.getElementById(id);\n    card.classList.toggle('open');\n  }\n  // Open first card by default\n  document.getElementById('era-indg').classList.add('open');\n</script>\n\n",
    "styles": "\n  .dq-article-document {\n    --bg: #0f0f13;\n    --surface: #17171e;\n    --border: #2a2a38;\n    --text: #e8e6f0;\n    --muted: #8a8aa0;\n    --accent: #c8a96e;\n    --accent2: #7eb8c8;\n\n    --indg:  #a07850;\n    --germ:  #7890b0;\n    --ahd:   #6878c0;\n    --mhd:   #5898a8;\n    --fnhd:  #58a870;\n    --nhd:   #c8a050;\n    --mod:   #c06860;\n\n    --indg-bg:  rgba(160,120,80,0.08);\n    --germ-bg:  rgba(120,144,176,0.08);\n    --ahd-bg:   rgba(104,120,192,0.08);\n    --mhd-bg:   rgba(88,152,168,0.08);\n    --fnhd-bg:  rgba(88,168,112,0.08);\n    --nhd-bg:   rgba(200,160,80,0.08);\n    --mod-bg:   rgba(192,104,96,0.08);\n  }\n\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n  .dq-article-document {\n    background: var(--bg);\n    color: var(--text);\n    font-family: 'Source Sans 3', sans-serif;\n    font-weight: 300;\n    line-height: 1.78;\n    min-height: 100vh;\n  }\n\n  /* ── HERO ── */\n  .hero {\n    position: relative;\n    padding: 90px 24px 68px;\n    text-align: center;\n    overflow: hidden;\n  }\n  .hero::before {\n    content: '';\n    position: absolute;\n    inset: 0;\n    background:\n      radial-gradient(ellipse 80% 55% at 50% 0%, rgba(200,169,110,0.14) 0%, transparent 68%),\n      radial-gradient(ellipse 50% 40% at 15% 90%, rgba(104,120,192,0.10) 0%, transparent 60%),\n      radial-gradient(ellipse 40% 35% at 85% 70%, rgba(192,104,96,0.08) 0%, transparent 55%);\n    pointer-events: none;\n  }\n  .hero-eyebrow {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.24em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 18px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.1s forwards;\n  }\n  .hero h1 {\n    font-family: 'Playfair Display', serif;\n    font-size: clamp(2.4rem, 6vw, 4.8rem);\n    font-weight: 900;\n    line-height: 1.08;\n    margin-bottom: 22px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.25s forwards;\n  }\n  .hero h1 em { font-style: normal; color: var(--accent); }\n  .hero-sub {\n    max-width: 660px;\n    margin: 0 auto 44px;\n    color: var(--muted);\n    font-size: 1.08rem;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.4s forwards;\n  }\n\n  /* ── ERA PILLS ── */\n  .era-strip {\n    display: flex;\n    justify-content: center;\n    flex-wrap: wrap;\n    gap: 7px;\n    margin-bottom: 10px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.55s forwards;\n  }\n  .era-pill {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    font-weight: 600;\n    padding: 4px 13px;\n    border-radius: 20px;\n    border: 1.5px solid currentColor;\n    white-space: nowrap;\n  }\n  .pill-indg  { color: var(--indg); }\n  .pill-germ  { color: var(--germ); }\n  .pill-ahd   { color: var(--ahd); }\n  .pill-mhd   { color: var(--mhd); }\n  .pill-fnhd  { color: var(--fnhd); }\n  .pill-nhd   { color: var(--nhd); }\n  .pill-mod   { color: var(--mod); }\n\n  .era-sublabel {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.16em;\n    color: var(--muted);\n    text-align: center;\n    margin-bottom: 38px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.65s forwards;\n  }\n\n  /* ── TIMELINE BAR ── */\n  .timeline-bar-wrap {\n    max-width: 880px;\n    margin: 0 auto;\n    padding: 28px 24px 0;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.75s forwards;\n  }\n  .timeline-bar {\n    display: flex;\n    height: 10px;\n    border-radius: 5px;\n    overflow: hidden;\n    margin-bottom: 10px;\n  }\n  .tb-seg { height: 100%; }\n  .tb-indg  { flex: 0.6; background: var(--indg); }\n  .tb-germ  { flex: 0.8; background: var(--germ); }\n  .tb-ahd   { flex: 1.2; background: var(--ahd); }\n  .tb-mhd   { flex: 1;   background: var(--mhd); }\n  .tb-fnhd  { flex: 1.2; background: var(--fnhd); }\n  .tb-nhd   { flex: 1.5; background: var(--nhd); }\n  .tb-mod   { flex: 2;   background: var(--mod); }\n  .timeline-labels {\n    display: flex;\n    justify-content: space-between;\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 9px;\n    color: var(--muted);\n    gap: 2px;\n  }\n  .timeline-labels span { text-align: center; flex: 1; }\n\n  /* ── MAIN CONTAINER ── */\n  .container {\n    max-width: 900px;\n    margin: 0 auto;\n    padding: 0 24px 90px;\n  }\n\n  /* ── SECTION HEADER ── */\n  .section-header {\n    display: flex;\n    align-items: center;\n    gap: 16px;\n    margin: 62px 0 32px;\n  }\n  .section-header::after {\n    content: '';\n    flex: 1;\n    height: 1px;\n    background: var(--border);\n  }\n  .section-header h2 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.2em;\n    text-transform: uppercase;\n    color: var(--muted);\n    white-space: nowrap;\n  }\n\n  /* ── ERA CARD ── */\n  .era-card {\n    border: 1px solid var(--border);\n    border-radius: 16px;\n    overflow: hidden;\n    margin-bottom: 28px;\n    opacity: 0;\n    animation: fadeUp 0.5s ease forwards;\n    transition: border-color 0.25s;\n  }\n  .era-card:nth-child(1) { animation-delay: 0.05s; }\n  .era-card:nth-child(2) { animation-delay: 0.12s; }\n  .era-card:nth-child(3) { animation-delay: 0.19s; }\n  .era-card:nth-child(4) { animation-delay: 0.26s; }\n  .era-card:nth-child(5) { animation-delay: 0.33s; }\n  .era-card:nth-child(6) { animation-delay: 0.40s; }\n  .era-card:nth-child(7) { animation-delay: 0.47s; }\n\n  .era-card-header {\n    display: grid;\n    grid-template-columns: auto 1fr auto;\n    align-items: center;\n    gap: 20px;\n    padding: 26px 30px 22px;\n    cursor: pointer;\n    user-select: none;\n  }\n  .era-year-block {\n    text-align: center;\n    min-width: 72px;\n  }\n  .era-abbr {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.6rem;\n    font-weight: 900;\n    line-height: 1;\n    display: block;\n    margin-bottom: 3px;\n  }\n  .era-date {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 9px;\n    color: var(--muted);\n    letter-spacing: 0.05em;\n    white-space: nowrap;\n  }\n  .era-title {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.32rem;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 4px;\n  }\n  .era-subtitle { font-size: 0.86rem; color: var(--muted); }\n  .era-toggle {\n    font-size: 22px;\n    color: var(--muted);\n    transition: transform 0.3s;\n    line-height: 1;\n  }\n  .era-card.open .era-toggle { transform: rotate(180deg); }\n\n  .era-.dq-article-document {\n    padding: 0 30px;\n    max-height: 0;\n    overflow: hidden;\n    transition: max-height 0.5s ease, padding 0.3s ease;\n  }\n  .era-card.open .era-.dq-article-document {\n    max-height: 3500px;\n    padding-bottom: 30px;\n  }\n\n  /* ── DESCRIPTION ── */\n  .era-description {\n    font-size: 0.97rem;\n    color: var(--muted);\n    margin-bottom: 24px;\n    line-height: 1.82;\n    padding: 16px 20px;\n    background: rgba(255,255,255,0.025);\n    border-radius: 10px;\n    border-left: 3px solid currentColor;\n  }\n\n  /* ── GRID ── */\n  .era-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 20px;\n    margin-bottom: 20px;\n  }\n  @media (max-width: 640px) {\n    .era-grid { grid-template-columns: 1fr; }\n    .era-card-header { gap: 12px; padding: 20px 20px 18px; }\n    .era-.dq-article-document { padding: 0 20px; }\n    .era-card.open .era-.dq-article-document { padding-bottom: 20px; }\n  }\n\n  .era-block {\n    background: var(--surface);\n    border-radius: 10px;\n    padding: 18px 20px;\n  }\n  .era-block h4 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 13px;\n  }\n  .era-block ul {\n    list-style: none;\n    display: flex;\n    flex-direction: column;\n    gap: 8px;\n  }\n  .era-block ul li {\n    font-size: 0.91rem;\n    padding-left: 20px;\n    position: relative;\n    color: var(--text);\n    line-height: 1.65;\n  }\n  .era-block ul li::before {\n    content: '→';\n    position: absolute;\n    left: 0;\n    font-size: 0.75rem;\n    top: 2px;\n  }\n  .era-block-full { grid-column: 1 / -1; }\n\n  /* ── TAGS ── */\n  .feature-tags {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n  }\n  .feature-tag {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    padding: 4px 11px;\n    border-radius: 6px;\n    background: rgba(255,255,255,0.05);\n    border: 1px solid var(--border);\n    color: var(--muted);\n  }\n\n  /* ── TEXT EXAMPLES ── */\n  .text-example {\n    background: rgba(255,255,255,0.03);\n    border: 1px solid var(--border);\n    border-left: 3px solid currentColor;\n    border-radius: 0 10px 10px 0;\n    padding: 14px 18px;\n    margin-bottom: 12px;\n  }\n  .text-example .original {\n    font-family: 'Playfair Display', serif;\n    font-style: italic;\n    font-size: 1rem;\n    color: var(--text);\n    margin-bottom: 6px;\n    line-height: 1.6;\n  }\n  .text-example .translation {\n    font-size: 0.82rem;\n    color: var(--muted);\n    line-height: 1.5;\n  }\n  .text-example .source {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 9px;\n    color: var(--muted);\n    letter-spacing: 0.1em;\n    margin-top: 6px;\n    opacity: 0.7;\n  }\n\n  /* ── ERA COLORS ── */\n  .lv-indg { color: var(--indg); border-color: rgba(160,120,80,0.22); }\n  .lv-germ { color: var(--germ); border-color: rgba(120,144,176,0.22); }\n  .lv-ahd  { color: var(--ahd);  border-color: rgba(104,120,192,0.22); }\n  .lv-mhd  { color: var(--mhd);  border-color: rgba(88,152,168,0.22); }\n  .lv-fnhd { color: var(--fnhd); border-color: rgba(88,168,112,0.22); }\n  .lv-nhd  { color: var(--nhd);  border-color: rgba(200,160,80,0.22); }\n  .lv-mod  { color: var(--mod);  border-color: rgba(192,104,96,0.22); }\n\n  .era-card.lv-indg:hover { border-color: var(--indg); }\n  .era-card.lv-germ:hover { border-color: var(--germ); }\n  .era-card.lv-ahd:hover  { border-color: var(--ahd); }\n  .era-card.lv-mhd:hover  { border-color: var(--mhd); }\n  .era-card.lv-fnhd:hover { border-color: var(--fnhd); }\n  .era-card.lv-nhd:hover  { border-color: var(--nhd); }\n  .era-card.lv-mod:hover  { border-color: var(--mod); }\n\n  .text-example.lv-ahd  { border-color: var(--ahd); }\n  .text-example.lv-mhd  { border-color: var(--mhd); }\n  .text-example.lv-fnhd { border-color: var(--fnhd); }\n  .text-example.lv-nhd  { border-color: var(--nhd); }\n  .text-example.lv-mod  { border-color: var(--mod); }\n\n  .era-description.lv-indg { border-color: var(--indg); }\n  .era-description.lv-germ { border-color: var(--germ); }\n  .era-description.lv-ahd  { border-color: var(--ahd); }\n  .era-description.lv-mhd  { border-color: var(--mhd); }\n  .era-description.lv-fnhd { border-color: var(--fnhd); }\n  .era-description.lv-nhd  { border-color: var(--nhd); }\n  .era-description.lv-mod  { border-color: var(--mod); }\n\n  /* ── NOTICE ── */\n  .notice {\n    background: rgba(200,169,110,0.07);\n    border: 1px solid rgba(200,169,110,0.22);\n    border-radius: 10px;\n    padding: 18px 22px;\n    font-size: 0.89rem;\n    color: var(--muted);\n    margin-bottom: 26px;\n    line-height: 1.75;\n  }\n  .notice strong { color: var(--accent); }\n\n  /* ── FACT BOX ── */\n  .fact-box {\n    background: rgba(126,184,200,0.06);\n    border: 1px solid rgba(126,184,200,0.18);\n    border-radius: 10px;\n    padding: 16px 20px;\n    margin-bottom: 20px;\n    font-size: 0.88rem;\n    color: var(--muted);\n    line-height: 1.7;\n  }\n  .fact-box strong { color: var(--accent2); }\n\n  /* ── COMPARISON TABLE ── */\n  .compare-table {\n    width: 100%;\n    border-collapse: collapse;\n    margin-bottom: 28px;\n    font-size: 0.88rem;\n  }\n  .compare-table th {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.15em;\n    text-transform: uppercase;\n    color: var(--muted);\n    text-align: left;\n    padding: 12px 16px;\n    border-bottom: 1px solid var(--border);\n    background: var(--surface);\n  }\n  .compare-table td {\n    padding: 12px 16px;\n    border-bottom: 1px solid var(--border);\n    vertical-align: top;\n    line-height: 1.55;\n  }\n  .compare-table tr:last-child td { border-bottom: none; }\n  .compare-table tr:hover td { background: rgba(255,255,255,0.02); }\n  .compare-table td:first-child {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    color: var(--accent);\n    white-space: nowrap;\n  }\n\n  /* ── FAMILY TREE ── */\n  .family-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 1px;\n    background: var(--border);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    overflow: hidden;\n    margin-bottom: 28px;\n  }\n  @media (max-width: 600px) { .family-grid { grid-template-columns: 1fr; } }\n  .fg-cell {\n    background: var(--surface);\n    padding: 20px 18px;\n    text-align: center;\n  }\n  .fg-icon { font-size: 26px; margin-bottom: 8px; }\n  .fg-label {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 6px;\n  }\n  .fg-langs {\n    font-size: 0.84rem;\n    color: var(--muted);\n    line-height: 1.6;\n  }\n\n  /* ── KEY FACTS GRID ── */\n  .keyfact-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 16px;\n    margin-bottom: 28px;\n  }\n  @media (max-width: 600px) { .keyfact-grid { grid-template-columns: 1fr; } }\n  .keyfact-card {\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    padding: 20px;\n  }\n  .keyfact-icon { font-size: 24px; margin-bottom: 10px; }\n  .keyfact-title {\n    font-weight: 600;\n    font-size: 0.96rem;\n    margin-bottom: 6px;\n  }\n  .keyfact-desc { font-size: 0.85rem; color: var(--muted); line-height: 1.65; }\n\n  /* ── FOOTER ── */\n  footer {\n    border-top: 1px solid var(--border);\n    padding: 36px 24px;\n    text-align: center;\n    color: var(--muted);\n    font-size: 0.83rem;\n    line-height: 1.8;\n  }\n  footer a { color: var(--accent); text-decoration: none; }\n  footer a:hover { text-decoration: underline; }\n\n  /* ── ANIMATIONS ── */\n  @keyframes fadeUp {\n    from { opacity: 0; transform: translateY(18px); }\n    to   { opacity: 1; transform: translateY(0); }\n  }\n\n  /* ── LAUTVS TABLE ── */\n  .laut-grid {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 1px;\n    background: var(--border);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    overflow: hidden;\n    margin-bottom: 20px;\n  }\n  @media (max-width: 580px) { .laut-grid { grid-template-columns: 1fr 1fr; } }\n  .laut-cell {\n    background: var(--surface);\n    padding: 14px 12px;\n    text-align: center;\n  }\n  .laut-from {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 15px;\n    font-weight: 600;\n    color: var(--germ);\n    margin-bottom: 4px;\n  }\n  .laut-arrow { font-size: 11px; color: var(--muted); margin-bottom: 4px; }\n  .laut-to {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 15px;\n    font-weight: 600;\n    color: var(--fnhd);\n  }\n  .laut-ex { font-size: 0.75rem; color: var(--muted); margin-top: 5px; }\n"
  },
  "pruefungen-goethe-telc-testdaf": {
    "content": "\n\n<!-- ════════════════════ HERO ════════════════════ -->\n<header class=\"hero\">\n  <p class=\"hero-eyebrow\">Deutschprüfungen · Goethe · telc · ÖSD · TestDaF · DSH · DTZ</p>\n  <h1>Deutsche<br><em>Sprachprüfungen</em><br>A1 – C2</h1>\n  <p class=\"hero-sub\">Aufbau, Ablauf, Zeitangaben und gezielte Vorbereitung für alle wichtigen Deutschzertifikate — vollständig und faktisch geprüft.</p>\n\n  <div class=\"provider-strip\">\n    <span class=\"prov-pill pill-goethe\">Goethe-Institut</span>\n    <span class=\"prov-pill pill-telc\">telc</span>\n    <span class=\"prov-pill pill-oesd\">ÖSD</span>\n    <span class=\"prov-pill pill-dtz\">DTZ</span>\n    <span class=\"prov-pill pill-testdaf\">TestDaF</span>\n    <span class=\"prov-pill pill-dsh\">DSH</span>\n  </div>\n  <p class=\"hero-sub2\" style=\"margin-top:10px;\">Niveau A1 · A2 · B1 · B2 · C1 · C2 nach GER/CEFR</p>\n</header>\n\n<!-- ════════════════════ 4 SKILLS BAR ════════════════════ -->\n<div class=\"container\" style=\"max-width:880px; padding-bottom:0;\">\n  <div class=\"skill-overview\">\n    <div class=\"skill-bar-row\">\n      <div class=\"skill-cell\">\n        <div class=\"skill-icon\">🎧</div>\n        <div class=\"skill-name s-listen\">Hören</div>\n        <div class=\"skill-desc\">Hörverstehen — gesprochene Texte, Dialoge, Nachrichten, Ansagen verstehen</div>\n      </div>\n      <div class=\"skill-cell\">\n        <div class=\"skill-icon\">📖</div>\n        <div class=\"skill-name s-read\">Lesen</div>\n        <div class=\"skill-desc\">Leseverstehen — Texte, Artikel, Formulare, E-Mails verstehen und auswerten</div>\n      </div>\n      <div class=\"skill-cell\">\n        <div class=\"skill-icon\">✍️</div>\n        <div class=\"skill-name s-write\">Schreiben</div>\n        <div class=\"skill-desc\">Schriftlicher Ausdruck — Briefe, E-Mails, Berichte, Stellungnahmen, Essays verfassen</div>\n      </div>\n      <div class=\"skill-cell\">\n        <div class=\"skill-icon\">🗣️</div>\n        <div class=\"skill-name s-speak\">Sprechen</div>\n        <div class=\"skill-desc\">Mündlicher Ausdruck — Monolog, Dialog, Diskussion, Präsentation, Reaktion</div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- ════════════════════ PRÜFUNGSANBIETER ════════════════════ -->\n<div class=\"container\">\n\n  <div class=\"section-header\"><h2>Prüfungsanbieter im Detail</h2></div>\n\n  <!-- ─── GOETHE ─── -->\n  <div class=\"prov-card lv-goethe\" id=\"prov-goethe\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-goethe')\">\n      <div class=\"prov-logo\">Goethe</div>\n      <div>\n        <p class=\"prov-title\">Goethe-Institut — Goethe-Zertifikat</p>\n        <p class=\"prov-subtitle\">A1 – C2 · International anerkannt · Modular aufgebaut</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-goethe\">\n        Das <strong>Goethe-Zertifikat</strong> ist die weltweit bekannteste und am weitesten verbreitete Deutschprüfung. Sie wird vom Goethe-Institut herausgegeben — einer deutschen Kulturinstitution mit Präsenz in über 90 Ländern. Die Prüfungen decken alle Niveaustufen von A1 bis C2 ab und sind nach dem GER/CEFR-Rahmen strukturiert. Ein zentrales Merkmal ist die <strong>modulare Struktur</strong>: Jedes Niveau besteht aus vier klar getrennten Modulen (Lesen, Hören, Schreiben, Sprechen), die teilweise auch einzeln absolviert werden können. Benotung: Pro Modul sind maximal 100 Punkte erreichbar; Bestehensgrenze liegt bei 60 Punkten (60 %) pro Modul.\n      </p>\n\n      <div class=\"notice\"><strong>Anerkennung:</strong> Goethe-Zertifikate werden weltweit von Behörden, Universitäten und Arbeitgebern anerkannt — u. a. für Visaverfahren, Einbürgerung, Studium und Beruf in Deutschland, Österreich und der Schweiz.</div>\n\n      <!-- Niveau-Übersicht -->\n      <div class=\"p-block p-block-full\" style=\"margin-bottom:18px;\">\n        <h4>Prüfungsaufbau nach Niveau — Goethe-Zertifikat</h4>\n        <table class=\"level-table\">\n          <thead><tr>\n            <th>Niveau</th><th>Hören</th><th>Lesen</th><th>Schreiben</th><th>Sprechen</th><th>Gesamt</th>\n          </tr></thead>\n          <tbody>\n            <tr>\n              <td><strong style=\"color:var(--a1c)\">A1</strong></td>\n              <td>ca. 20 Min.</td><td>ca. 25 Min.</td><td>ca. 20 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 80 Min.</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--a2c)\">A2</strong></td>\n              <td>ca. 25 Min.</td><td>ca. 30 Min.</td><td>ca. 30 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 100 Min.</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--b1c)\">B1</strong></td>\n              <td>ca. 40 Min.</td><td>ca. 45 Min.</td><td>ca. 60 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 160 Min.</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--b2c)\">B2</strong></td>\n              <td>ca. 40 Min.</td><td>ca. 65 Min.</td><td>ca. 75 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 195 Min.</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c1c)\">C1</strong></td>\n              <td>ca. 40 Min.</td><td>ca. 70 Min.</td><td>ca. 80 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 205 Min.</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c2c)\">C2</strong></td>\n              <td>ca. 40 Min.</td><td>ca. 70 Min.</td><td>ca. 80 Min.</td><td>ca. 15 Min.</td>\n              <td>ca. 205 Min.</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Aufgabentypen — Lesen &amp; Hören</h4>\n          <ul>\n            <li>Zuordnungsaufgaben (Welche Aussage passt zu welchem Text?)</li>\n            <li>Multiple Choice (eine oder mehrere richtige Antworten)</li>\n            <li>Richtig / Falsch / Nicht im Text</li>\n            <li>Lückentexte (passendes Wort einsetzen)</li>\n            <li>Reihenfolge-Aufgaben (Aussagen in Reihenfolge bringen)</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Aufgabentypen — Schreiben &amp; Sprechen</h4>\n          <ul>\n            <li>Schreiben: formal/informell Brief oder E-Mail (A1–B1)</li>\n            <li>Schreiben: Stellungnahme, Bericht, Erörterung (B2–C2)</li>\n            <li>Sprechen A1/A2: Vorstellen, einfacher Dialog, Bildkarte</li>\n            <li>Sprechen B1+: Meinung äußern, Partner-Diskussion, Präsentation</li>\n            <li>Sprechen meist als Paarprüfung — 2 Kandidaten + 2 Prüfer</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Bewertung &amp; Bestehen</h4>\n          <ul>\n            <li>Jedes Modul: max. 100 Punkte, Bestehensgrenze 60 Punkte</li>\n            <li>Alle vier Module müssen einzeln mit ≥ 60 Punkten bestanden werden</li>\n            <li>Nicht bestandene Module können nachgeholt werden (modulare Zertifizierung)</li>\n            <li>Gesamtergebnis: Summe aller vier Module (max. 400 Punkte)</li>\n            <li>Noten: Sehr gut (≥ 90%), Gut (≥ 80%), Befriedigend (≥ 70%), Ausreichend (≥ 60%)</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Anmeldung &amp; Prüfungsablauf</h4>\n          <ul>\n            <li>Anmeldung beim lokalen Goethe-Institut oder autorisierten Prüfungszentrum</li>\n            <li>Gültiger Lichtbildausweis (Reisepass oder Personalausweis) erforderlich</li>\n            <li>Schriftliche Prüfung und mündliche Prüfung häufig an zwei verschiedenen Tagen</li>\n            <li>Ergebnisse in der Regel 4–6 Wochen nach der Prüfung</li>\n            <li>Zertifikat ist zeitlich unbegrenzt gültig (kein Verfalldatum)</li>\n          </ul>\n        </div>\n      </div>\n\n      <div class=\"warn-box\"><strong>⚡ Wichtig für A1:</strong> Das Goethe-Zertifikat A1: Start Deutsch 1 wird speziell für den Familiennachzug nach Deutschland benötigt. Es gibt auch eine Variante für Jugendliche (<em>Fit in Deutsch 1</em>).</div>\n    </div>\n  </div>\n\n  <!-- ─── TELC ─── -->\n  <div class=\"prov-card lv-telc\" id=\"prov-telc\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-telc')\">\n      <div class=\"prov-logo\">telc</div>\n      <div>\n        <p class=\"prov-title\">telc — The European Language Certificates</p>\n        <p class=\"prov-subtitle\">A1 – C1 · Integrationsrelevant · Viele Prüfungszentren in DE/AT</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-telc\">\n        <strong>telc</strong> (The European Language Certificates, Sitz in Frankfurt am Main) bietet standardisierte Sprachprüfungen für viele Sprachen und Niveaustufen an. Im Deutschen-Bereich ist telc besonders relevant für den <strong>Integrations- und Migrationskontext</strong>: Die telc-Prüfungen werden von den deutschen Behörden, dem BAMF und vielen Arbeitgebern anerkannt. Ein Besonderheit ist die breite Palette an berufs- und branchenspezifischen Prüfungen (z. B. <em>telc Deutsch B2 Pflege</em> für Pflegepersonal oder <em>telc Deutsch B2 Beruf</em>). telc-Prüfungen sind in Aufbau und Bewertung etwas anders strukturiert als Goethe-Prüfungen: Es gibt einen schriftlichen Teil (Sprachbausteine + rezeptive + produktive Fertigkeiten) und einen mündlichen Teil.\n      </p>\n\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Aufbau telc Deutsch B1 (Beispiel)</h4>\n          <ul>\n            <li><strong>Schriftliche Prüfung (~90 Min.):</strong></li>\n            <li>Leseverstehen: 3 Teile, ca. 30 Min.</li>\n            <li>Sprachbausteine: 2 Teile (Lückentext-Grammatik), ca. 15 Min.</li>\n            <li>Hörverstehen: 3 Teile, ca. 25 Min.</li>\n            <li>Schreiben: 1 Text (Brief/E-Mail), ca. 30 Min.</li>\n            <li><strong>Mündliche Prüfung (~15 Min.):</strong></li>\n            <li>Vorstellung, gemeinsame Aufgabe, Präsentation</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Besonderheit: Sprachbausteine</h4>\n          <ul>\n            <li>telc-Prüfungen enthalten „Sprachbausteine\" — ein eigener Prüfungsteil</li>\n            <li>Lückentexte, bei denen Grammatik und Wortschatz direkt getestet werden</li>\n            <li>Teil 1: offene Lücken (Wort selbst einsetzen)</li>\n            <li>Teil 2: Multiple Choice aus drei Optionen</li>\n            <li>Dieser Teil fehlt beim Goethe-Zertifikat — ist ein telc-Spezifikum</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>telc-Prüfungen — Übersicht Niveaus</h4>\n          <ul>\n            <li><strong style=\"color:var(--a1c)\">A1</strong> telc Deutsch A1</li>\n            <li><strong style=\"color:var(--a2c)\">A2</strong> telc Deutsch A2 / A2+ Schule</li>\n            <li><strong style=\"color:var(--b1c)\">B1</strong> telc Deutsch B1 / B1+ Beruf</li>\n            <li><strong style=\"color:var(--b2c)\">B2</strong> telc Deutsch B2 / B2 Medizin / B2 Pflege / B2 Beruf</li>\n            <li><strong style=\"color:var(--c1c)\">C1</strong> telc Deutsch C1 / C1 Hochschule</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Bewertung &amp; Bestehen</h4>\n          <ul>\n            <li>Schriftlicher Teil: max. 150 Punkte (je nach Niveau)</li>\n            <li>Mündlicher Teil: max. 45 Punkte (je nach Niveau)</li>\n            <li>Bestehensgrenze: 60% der Gesamtpunktzahl</li>\n            <li>Schriftlich und mündlich werden separat bewertet</li>\n            <li>Beide Teile müssen bestanden sein — bei Nicht-Bestehen eines Teils gilt die Prüfung als nicht bestanden</li>\n          </ul>\n        </div>\n      </div>\n      <div class=\"notice\"><strong>Berufsbezeichnungen:</strong> Für ausländische Fachkräfte in Pflege, Medizin und Sozialarbeit gibt es spezialisierte telc-Prüfungen mit berufsrelevantem Wortschatz und Situationen. Diese werden von vielen Ärztekammern und Krankenhäusern explizit verlangt.</div>\n    </div>\n  </div>\n\n  <!-- ─── ÖSD ─── -->\n  <div class=\"prov-card lv-oesd\" id=\"prov-oesd\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-oesd')\">\n      <div class=\"prov-logo\">ÖSD</div>\n      <div>\n        <p class=\"prov-title\">ÖSD — Österreichisches Sprachdiplom Deutsch</p>\n        <p class=\"prov-subtitle\">A1 – C2 · Stark in Österreich · Modular zertifizierbar</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-oesd\">\n        Das <strong>ÖSD</strong> (Österreichisches Sprachdiplom Deutsch) ist eine österreichische Bildungsinstitution, die Deutschprüfungen nach GER/CEFR für alle Niveaus anbietet. ÖSD-Zertifikate werden in Österreich, Deutschland und der Schweiz von Behörden anerkannt und sind international verbreitet. Ein besonderes Merkmal: Die Prüfungen sind klar in <strong>schriftliches Modul</strong> (Lesen + Hören + Schreiben) und <strong>mündliches Modul</strong> (Sprechen) unterteilt — beide können getrennt abgelegt und zertifiziert werden. Das ÖSD legt besonderen Wert auf authentisches österreichisches Deutsch und realitätsnahe Kommunikationssituationen.\n      </p>\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Aufbau ÖSD B2 (Beispiel)</h4>\n          <ul>\n            <li><strong>Schriftliches Modul (~165 Min.):</strong></li>\n            <li>Leseverstehen: 3–4 Aufgaben, ca. 60 Min.</li>\n            <li>Hörverstehen: 3–4 Aufgaben, ca. 30 Min.</li>\n            <li>Schriftlicher Ausdruck: Stellungnahme oder Brief, ca. 75 Min.</li>\n            <li><strong>Mündliches Modul (~20 Min. pro Person):</strong></li>\n            <li>Monologischer Teil + Interaktion mit Partner</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Besonderheiten ÖSD</h4>\n          <ul>\n            <li>Modulare Zertifizierung: schriftlich und mündlich können <em>getrennt</em> zertifiziert werden</li>\n            <li>Das schriftliche Zertifikat gilt 3 Jahre (für spätere mündliche Ergänzung)</li>\n            <li>Österreichisches Standarddeutsch in Texten und Hörmaterial</li>\n            <li>ÖSD-Zertifikate erfüllen die Anforderungen für den österreichischen Aufenthaltstitel</li>\n            <li>Auch spezifische Prüfungen für Jugendliche (KID = Kindersprachdiplom)</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Niveaus und Bezeichnungen</h4>\n          <ul>\n            <li><strong style=\"color:var(--a1c)\">A1</strong> ÖSD Zertifikat A1</li>\n            <li><strong style=\"color:var(--a2c)\">A2</strong> ÖSD Zertifikat A2</li>\n            <li><strong style=\"color:var(--b1c)\">B1</strong> ÖSD Zertifikat B1</li>\n            <li><strong style=\"color:var(--b2c)\">B2</strong> ÖSD Zertifikat B2</li>\n            <li><strong style=\"color:var(--c1c)\">C1</strong> ÖSD Zertifikat C1</li>\n            <li><strong style=\"color:var(--c2c)\">C2</strong> ÖSD Zertifikat C2</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Bewertung ÖSD</h4>\n          <ul>\n            <li>Schriftliches Modul: max. 100 Punkte, Bestehensgrenze 60%</li>\n            <li>Mündliches Modul: max. 100 Punkte, Bestehensgrenze 60%</li>\n            <li>Bewertungskriterien Sprechen: Kommunikativität, Korrektheit, Spektrum</li>\n            <li>Bewertungskriterien Schreiben: Inhalt, Aufbau, Sprachrichtigkeit, Wortschatz</li>\n            <li>Gesamtzertifikat: beide Module müssen bestanden sein</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── DTZ ─── -->\n  <div class=\"prov-card lv-dtz\" id=\"prov-dtz\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-dtz')\">\n      <div class=\"prov-logo\">DTZ</div>\n      <div>\n        <p class=\"prov-title\">DTZ — Deutsch-Test für Zuwanderer</p>\n        <p class=\"prov-subtitle\">A2–B1 · BAMF-Integrationskurs · Aufenthaltsrecht</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-dtz\">\n        Der <strong>DTZ</strong> (Deutsch-Test für Zuwanderer) ist eine staatlich vorgeschriebene Prüfung, die am Ende eines <strong>BAMF-Integrationskurses</strong> abgelegt wird. Er ist kein allgemeines Sprachzertifikat, sondern eine praxisorientierte Prüfung, die auf das Leben in Deutschland ausgerichtet ist. Das Ergebnis wird als <strong>A2 oder B1</strong> ausgewiesen (oder als „unter A2\", wenn das Mindestniveau nicht erreicht wird). Der DTZ wird von verschiedenen Prüfungsorganisationen durchgeführt (u. a. telc, Goethe-Institut). Die Prüfung hat direkten Einfluss auf aufenthaltsrechtliche Entscheidungen.\n      </p>\n\n      <div class=\"warn-box\"><strong>⚡ Aufenthaltsrechtliche Relevanz:</strong> Das Ergebnis des DTZ beeinflusst direkt die aufenthaltsrechtliche Situation in Deutschland. B1 ist Voraussetzung für die unbefristete Niederlassungserlaubnis (§ 9 AufenthG). Wer nur A2 erreicht, muss in manchen Fällen weitere Kurse absolvieren.</div>\n\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Aufbau DTZ — Schriftliche Prüfung</h4>\n          <ul>\n            <li>Gesamtdauer schriftlich: ca. 100 Minuten</li>\n            <li><strong>Hören:</strong> 3 Teile, Alltagsdialoge und Ansagen, ca. 25 Min.</li>\n            <li><strong>Lesen:</strong> 3 Teile, Formulare, Nachrichten, kurze Texte, ca. 45 Min.</li>\n            <li><strong>Schreiben:</strong> 1 Aufgabe — formelle Nachricht (Termin, Anfrage, Problem), ca. 30 Min.</li>\n            <li>Hören und Lesen werden zusammengezählt (gemeinsame Punktgrenze)</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Aufbau DTZ — Mündliche Prüfung</h4>\n          <ul>\n            <li>Dauer: ca. 15 Minuten pro Person</li>\n            <li>Teil 1: Vorstellen (Name, Herkunft, Beruf, Familie)</li>\n            <li>Teil 2: Alltagssituation aus Bildkarte beschreiben</li>\n            <li>Teil 3: Meinung zu einem Thema äußern, Reaktion auf Partner</li>\n            <li>Bewertet wird: Kommunikative Effizienz, nicht sprachliche Perfektion</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Typische Themen im DTZ</h4>\n          <ul>\n            <li>Arbeit und Beruf (Bewerbung, Arbeitsvertrag, Kollegen)</li>\n            <li>Wohnen und Nachbarn (Mietvertrag, Hausordnung)</li>\n            <li>Gesundheit und Arztbesuche</li>\n            <li>Ämter und Behörden (Anträge, Formulare)</li>\n            <li>Schule und Kindergarten (für Kinder)</li>\n            <li>Öffentlicher Nahverkehr, Einkaufen</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Bewertung &amp; Ergebnisse</h4>\n          <ul>\n            <li>Ergebnis: <strong>B1</strong> (höchstes), <strong>A2</strong>, oder <strong>unter A2</strong></li>\n            <li>Schreiben wird separat bewertet</li>\n            <li>Sprechen wird separat bewertet</li>\n            <li>Kein klassisches Notensystem — Einstufung nach Sprachniveau</li>\n            <li>Wiederholung möglich, wenn Ergebnis nicht ausreicht</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ─── TestDaF ─── -->\n  <div class=\"prov-card lv-testdaf\" id=\"prov-testdaf\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-testdaf')\">\n      <div class=\"prov-logo\">TDaF</div>\n      <div>\n        <p class=\"prov-title\">TestDaF — Test Deutsch als Fremdsprache</p>\n        <p class=\"prov-subtitle\">B2–C1 · Hochschulzugang · TDN-Stufensystem</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-testdaf\">\n        Der <strong>TestDaF</strong> ist eine Hochschulzugangsprüfung für internationale Studienbewerber an deutschen Universitäten und Fachhochschulen. Er wird vom TestDaF-Institut (Hagen) entwickelt und weltweit an autorisierten Testzentren angeboten. Das Besondere: Statt eines CEFR-Niveaus bekommt man für jede der vier Fertigkeiten eine <strong>TDN-Stufe</strong> (TestDaF-Niveaustufe) — TDN 3, TDN 4 oder TDN 5. Für die Hochschulzulassung wird in der Regel TDN 4 in allen vier Fertigkeiten verlangt (manche Hochschulen akzeptieren auch TDN 3 in einem Teil). TestDaF kann auch digital (dTestDaF) abgelegt werden.\n      </p>\n\n      <div class=\"p-block p-block-full\" style=\"margin-bottom:18px;\">\n        <h4>Das TDN-Stufensystem — Bedeutung der Stufen</h4>\n        <table class=\"level-table\">\n          <thead><tr><th>TDN-Stufe</th><th>Ungefähres CEFR-Niveau</th><th>Bedeutung</th><th>Hochschule</th></tr></thead>\n          <tbody>\n            <tr>\n              <td><strong style=\"color:var(--b2c)\">TDN 3</strong></td>\n              <td>B2 (unteres)</td>\n              <td>Grundlegende Kompetenz für akademische Kommunikation</td>\n              <td>Meist nicht ausreichend — von manchen HS akzeptiert</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c1c)\">TDN 4</strong></td>\n              <td>B2+ / C1 (unteres)</td>\n              <td>Gute Kompetenz — akademisch arbeitsfähig</td>\n              <td>Standard-Anforderung der meisten deutschen Hochschulen</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c2c)\">TDN 5</strong></td>\n              <td>C1 (oberes)</td>\n              <td>Sehr gute Kompetenz — nahezu akademisch muttersprachlich</td>\n              <td>Übertrifft die Anforderungen — immer ausreichend</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Aufbau TestDaF — 4 Teile</h4>\n          <ul>\n            <li><strong>Leseverstehen:</strong> 3 Aufgaben, ca. 60 Min. — akademische Texte, Tabellen, Schaubilder</li>\n            <li><strong>Hörverstehen:</strong> 3 Aufgaben, ca. 40 Min. — Vorlesung, Interview, Gespräch</li>\n            <li><strong>Schriftlicher Ausdruck:</strong> 1 Aufgabe, ca. 60 Min. — Diagramm beschreiben + Stellungnahme</li>\n            <li><strong>Mündlicher Ausdruck:</strong> 7 Aufgaben, ca. 35 Min. — als Tonaufnahme, kein Prüfer anwesend</li>\n            <li>Gesamtdauer: ca. 3 Stunden 15 Minuten (ohne Pausen)</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Besonderheit: Mündlicher Ausdruck ohne Prüfer</h4>\n          <ul>\n            <li>Der mündliche Teil wird <em>als Tonaufnahme</em> abgelegt — kein Gespräch mit Prüfer</li>\n            <li>7 Aufgaben zu akademischen Themen (Uni-Alltag, Graphiken, Diskussionen)</li>\n            <li>Vorbereitung: kurze Vorbereitungszeit pro Aufgabe (15–30 Sek.)</li>\n            <li>Sprechen: ca. 30–90 Sekunden pro Aufgabe</li>\n            <li>Bewertung durch geschulte Bewerter nach festen Kriterien</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Typische akademische Themen</h4>\n          <div class=\"tags\" style=\"margin-top:0;\">\n            <span class=\"tag\">Studium und Hochschule</span>\n            <span class=\"tag\">Umwelt und Klimawandel</span>\n            <span class=\"tag\">Gesellschaft und Politik</span>\n            <span class=\"tag\">Wirtschaft und Globalisierung</span>\n            <span class=\"tag\">Medizin und Gesundheit</span>\n            <span class=\"tag\">Technik und Innovation</span>\n            <span class=\"tag\">Statistiken und Diagramme</span>\n            <span class=\"tag\">Demografischer Wandel</span>\n          </div>\n        </div>\n        <div class=\"p-block\">\n          <h4>Vorbereitung TestDaF</h4>\n          <ul>\n            <li>Akademischen Wortschatz systematisch aufbauen (Definitionen, Ursache-Wirkung)</li>\n            <li>Diagramme beschreiben trainieren (Anstieg, Rückgang, Plateau)</li>\n            <li>Schnelles Lesen — Kernaussagen in langen Texten identifizieren</li>\n            <li>Mündliche Aufnahmen üben: strukturiert, ohne Zögern sprechen</li>\n            <li>Offizielle Modellsätze und frühere Prüfungen auf testdaf.de üben</li>\n          </ul>\n        </div>\n      </div>\n      <div class=\"notice\"><strong>Digital oder Papier?</strong> TestDaF kann seit 2023 auch als <em>dTestDaF</em> (digital, am Computer) abgelegt werden. Das Format ist inhaltlich identisch — nur die Durchführungsform unterscheidet sich.</div>\n    </div>\n  </div>\n\n  <!-- ─── DSH ─── -->\n  <div class=\"prov-card lv-dsh\" id=\"prov-dsh\">\n    <div class=\"prov-header\" onclick=\"toggleCard('prov-dsh')\">\n      <div class=\"prov-logo\">DSH</div>\n      <div>\n        <p class=\"prov-title\">DSH — Deutsche Sprachprüfung für den Hochschulzugang</p>\n        <p class=\"prov-subtitle\">B2–C1/C2 · Hochschulprüfung · Je nach Universität unterschiedlich</p>\n      </div>\n      <div class=\"prov-toggle\">▾</div>\n    </div>\n    <div class=\"prov-body\">\n      <p class=\"prov-description lv-dsh\">\n        Die <strong>DSH</strong> (Deutsche Sprachprüfung für den Hochschulzugang) ist eine <em>Hochschulprüfung</em> — sie wird direkt von der jeweiligen Universität oder Fachhochschule organisiert und abgenommen. Im Gegensatz zu TestDaF gibt es kein zentrales, einheitliches Format: Jede Hochschule entwickelt ihre eigenen Aufgaben, jedoch müssen alle DSH-Prüfungen den Rahmenbestimmungen der Hochschulrektorenkonferenz (HRK) entsprechen. Das Ergebnis ist nach DSH-Stufen gegliedert: <strong>DSH-1</strong>, <strong>DSH-2</strong> und <strong>DSH-3</strong>. Für die Zulassung zum Studium wird in der Regel DSH-2 verlangt.\n      </p>\n\n      <div class=\"p-block p-block-full\" style=\"margin-bottom:18px;\">\n        <h4>DSH-Stufen — Bedeutung und Anforderungen</h4>\n        <table class=\"level-table\">\n          <thead><tr><th>DSH-Stufe</th><th>Prozentuales Ergebnis</th><th>CEFR (ungefähr)</th><th>Studiumszulassung</th></tr></thead>\n          <tbody>\n            <tr>\n              <td><strong style=\"color:var(--b2c)\">DSH-1</strong></td>\n              <td>57 % – 66 %</td>\n              <td>ca. B2</td>\n              <td>Eingeschränkt — manche HS akzeptieren es mit Auflagen</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c1c)\">DSH-2</strong></td>\n              <td>67 % – 81 %</td>\n              <td>ca. C1</td>\n              <td>Standard-Zulassung — von allen deutschen Hochschulen anerkannt</td>\n            </tr>\n            <tr>\n              <td><strong style=\"color:var(--c2c)\">DSH-3</strong></td>\n              <td>82 % und mehr</td>\n              <td>ca. C1–C2</td>\n              <td>Sehr gut — übertrifft alle Anforderungen</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <div class=\"prov-grid\">\n        <div class=\"p-block\">\n          <h4>Schriftlicher Teil — typische Inhalte</h4>\n          <ul>\n            <li><strong>Hörverstehen:</strong> Vorlesung oder Vortrag (20–30 Min.), Notizen machen, dann Aufgaben lösen</li>\n            <li><strong>Leseverstehen:</strong> Wissenschaftlicher Text (800–1200 Wörter), Verstehens- und Transferaufgaben</li>\n            <li><strong>Wissenschaftliche Strukturen:</strong> Grammatik, Satzbau, Konnektoren in wissenschaftlichem Kontext</li>\n            <li><strong>Textproduktion:</strong> Zusammenfassung + argumentativer Text (~300–400 Wörter), ca. 60–70 Min.</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Mündlicher Teil</h4>\n          <ul>\n            <li>Dauer: ca. 20–30 Minuten (je nach Hochschule)</li>\n            <li>Kurzpräsentation zu einem Thema (5–10 Min. Vorbereitung)</li>\n            <li>Fachgespräch auf Basis des Präsentationsthemas</li>\n            <li>Prüfer: 2 Hochschuldozenten</li>\n            <li>Wichtig: Wenn schriftlicher Teil unter Mindestgrenze, gilt mündlich nicht mehr</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Wichtige Unterschiede zu TestDaF</h4>\n          <ul>\n            <li>DSH: Hochschuleigene Prüfung, nur an dieser HS gültig (in der Regel)</li>\n            <li>TestDaF: Zentral entwickelt, bundesweit und international gültig</li>\n            <li>DSH: Muss vor Ort an der Ziel-HS abgelegt werden</li>\n            <li>DSH: Format und Schwierigkeit variieren je nach Hochschule</li>\n            <li>TestDaF: Einheitlich — gleicher Standard weltweit</li>\n          </ul>\n        </div>\n        <div class=\"p-block\">\n          <h4>Vorbereitung DSH</h4>\n          <ul>\n            <li>Wissenschaftssprache intensiv üben (Definitionen, Kausalität, Schlussfolgerungen)</li>\n            <li>Vorlesungen hören und Notizen strukturiert mitschreiben</li>\n            <li>Zusammenfassungen schreiben — sachlich, in eigenen Worten</li>\n            <li>Grammatik Niveau C1: Partizipialkonstruktionen, Passiv, Nominalisierungen</li>\n            <li>Probeprüfungen der Ziel-Hochschule herunterladen und üben</li>\n          </ul>\n        </div>\n      </div>\n      <div class=\"warn-box\"><strong>⚡ Gültigkeitsdauer:</strong> Das DSH-Zertifikat wird normalerweise unbegrenzt ausgestellt, <strong>aber</strong>: Es gilt nur für die ausstellende Hochschule oder im besten Fall für alle deutschen Hochschulen — je nach Regelung. TestDaF ist immer bundesweit gültig.</div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ PRÜFUNGSTAG ════════════════════ -->\n  <div class=\"section-header\"><h2>So läuft ein Prüfungstag ab</h2></div>\n\n  <p style=\"color:var(--muted); margin-bottom:24px; font-size:0.95rem; line-height:1.75;\">\n    Unabhängig vom Anbieter folgt ein Prüfungstag immer einem ähnlichen Ablauf. Wer diesen Ablauf kennt, geht ruhiger und besser vorbereitet in die Prüfung.\n  </p>\n\n  <div class=\"day-timeline\" style=\"max-width:640px;\">\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 1 · Anmeldung</div>\n        <div class=\"dt-title\">Einlass und Identitätsprüfung</div>\n        <div class=\"dt-desc\">Anmeldung am Empfang des Prüfungszentrums. Gültiger Reisepass oder Personalausweis vorzeigen (kein Führerschein bei manchen Anbietern). Sitzplatznummer in Empfang nehmen. Keine Handys, Smartwatches oder Notizen erlaubt — alles abgeben oder ausschalten.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 2 · Einweisung</div>\n        <div class=\"dt-title\">Regeln und Ablauf erklären</div>\n        <div class=\"dt-desc\">Die Prüfungsleitung erklärt die Regeln: Kein Sprechen, kein Wörterbuch, kein Handy. Aufgabenhefte werden ausgeteilt, aber noch nicht geöffnet. Ruhig bleiben — auch wenn andere Kandidaten nervös wirken.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 3 · Hören</div>\n        <div class=\"dt-title\">Hörverstehen (meistens zuerst)</div>\n        <div class=\"dt-desc\">Meist der erste Prüfungsteil. Tonaufnahmen werden abgespielt — in der Regel zweimal. Notizen in Stichpunkten machen. Nicht den ganzen Satz aufschreiben — Schlüsselwörter, Zahlen, Namen reichen. Nicht in Panik geraten, wenn man etwas verpasst hat — beim zweiten Hören ergänzen.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 4 · Lesen</div>\n        <div class=\"dt-title\">Leseverstehen</div>\n        <div class=\"dt-desc\">Texte lesen und Aufgaben lösen. Strategie: erst Fragen lesen, dann gezielt im Text suchen. Nicht zu viel Zeit bei einer Aufgabe verbringen — weitergehen und zurückkehren. Zeit ist knapp kalkuliert.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 5 · Schreiben</div>\n        <div class=\"dt-title\">Schriftlicher Ausdruck</div>\n        <div class=\"dt-desc\">Einen Text verfassen — Brief, E-Mail, Stellungnahme oder Essay je nach Niveau. Immer: Aufgabe sorgfältig lesen, Struktur planen (2–3 Min.), dann schreiben. Am Ende nochmals korrigieren (5 Min. einplanen). Handschrift muss lesbar sein.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 6 · Pause</div>\n        <div class=\"dt-title\">Kurze Pause (je nach Zentrum)</div>\n        <div class=\"dt-desc\">15–30 Minuten Pause zwischen schriftlichem und mündlichem Teil (oder zwischen Tagen). Wasser trinken, durchatmen. Nicht mit anderen Kandidaten über Aufgaben sprechen — das erzeugt zusätzliche Nervosität.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\"></div><div class=\"dt-line\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\">Schritt 7 · Sprechen</div>\n        <div class=\"dt-title\">Mündliche Prüfung</div>\n        <div class=\"dt-desc\">Meist als Paarprüfung (zwei Kandidaten + zwei Prüfer) oder Einzelprüfung. Kurze Vorbereitungszeit auf das Thema (~5 Min.). Dann: Monolog, Dialog, Diskussion — je nach Niveau. Ruhig und strukturiert sprechen. Fehler sind erlaubt — Kommunikation zählt.</div>\n      </div>\n    </div>\n    <div class=\"dt-step\">\n      <div class=\"dt-left\"><div class=\"dt-dot\" style=\"border-color:var(--accent2);\"></div></div>\n      <div class=\"dt-content\">\n        <div class=\"dt-time\" style=\"color:var(--accent2);\">Schritt 8 · Ergebnis</div>\n        <div class=\"dt-title\">Warten auf das Ergebnis</div>\n        <div class=\"dt-desc\">Ergebnisse je nach Anbieter in 2–8 Wochen. Goethe und telc: oft 4–6 Wochen. TestDaF: ca. 6–8 Wochen. DSH: oft schneller (2–4 Wochen), da hochschulintern. Zertifikat wird per Post oder digital zugesandt.</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ PRÜFUNGSTAKTIK ════════════════════ -->\n  <div class=\"section-header\"><h2>Prüfungstaktik nach Fertigkeit</h2></div>\n\n  <div class=\"training-grid\">\n    <div class=\"tr-card s-listen\">\n      <div class=\"tr-icon\">🎧</div>\n      <div class=\"tr-title\">Hören — Strategie &amp; Training</div>\n      <div class=\"tr-body\">\n        <ul>\n          <li>Fragen <em>vor</em> dem Hören lesen — wissen, worauf man achten muss</li>\n          <li>Stichpunkte machen: Zahlen, Namen, Orte, Gründe, Daten</li>\n          <li>Beim zweiten Hören (wenn vorhanden) Lücken schließen und überprüfen</li>\n          <li>„Prüfungstempo\" trainieren — nicht nur langsame Podcasts hören</li>\n          <li>Bei unbekannten Wörtern: Kontext nutzen, nicht abbrechen</li>\n          <li>Typische Quellen: Deutsche Welle, Deutschlandfunk, ZDF Mediathek</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"tr-card s-read\">\n      <div class=\"tr-icon\">📖</div>\n      <div class=\"tr-title\">Lesen — Strategie &amp; Training</div>\n      <div class=\"tr-body\">\n        <ul>\n          <li>Zuerst Fragen lesen, dann gezielt im Text suchen (nicht alles gleich intensiv lesen)</li>\n          <li>Überschriften und erste Sätze jedes Absatzes für Struktur nutzen</li>\n          <li>Typische Aufgaben kennen: Richtig/Falsch, MC, Zuordnung, Lücken</li>\n          <li>Zeit einteilen: pro Aufgabe max. Zeit vorher schätzen, nicht hängen bleiben</li>\n          <li>Unbekannte Wörter aus Kontext erschließen — kein Wörterbuch</li>\n          <li>Zeitungen lesen: Zeit Online, Der Standard, Neue Zürcher Zeitung</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"tr-card s-write\">\n      <div class=\"tr-icon\">✍️</div>\n      <div class=\"tr-title\">Schreiben — Struktur &amp; Training</div>\n      <div class=\"tr-body\">\n        <ul>\n          <li><strong>A1–B1:</strong> Anrede → Zweck → 2–3 Infopunkte → Bitte/Frage → Gruß + Name</li>\n          <li><strong>B2–C2:</strong> Einleitung (These) → Hauptteil (Argumente, Beispiele) → Schluss</li>\n          <li>Immer: Aufgabe genau lesen — alle Punkte müssen behandelt werden</li>\n          <li>Konnektoren verwenden: <em>außerdem, allerdings, dennoch, einerseits…andererseits</em></li>\n          <li>Letzte 5 Minuten: Korrektur auf Rechtschreibung, Grammatik, Vollständigkeit</li>\n          <li>Schreibtraining: täglich 1 kurzen Text (E-Mail, Meinung, Zusammenfassung)</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"tr-card s-speak\">\n      <div class=\"tr-icon\">🗣️</div>\n      <div class=\"tr-title\">Sprechen — Technik &amp; Training</div>\n      <div class=\"tr-body\">\n        <ul>\n          <li>20–40 Redemittel auswendig lernen — diese ersetzen das Zögern</li>\n          <li>Zeitgefühl trainieren: 1 Min., 2 Min., 3 Min. sprechen (mit Stoppuhr)</li>\n          <li>Paarprüfung: aktiv reagieren — <em>„Da stimme ich zu…\", „Ich sehe das etwas anders…\"</em></li>\n          <li>Fehler nicht unterbrechen — weiter sprechen, am Ende korrigieren</li>\n          <li>Struktur: These → Begründung → Beispiel → Schluss (auch mündlich)</li>\n          <li>Laut sprechen üben — Handy aufnehmen und selbst zuhören</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ REDEMITTEL ════════════════════ -->\n  <div class=\"section-header\"><h2>Wichtige Redemittel für die mündliche Prüfung</h2></div>\n\n  <div class=\"redemittel-grid\">\n    <div class=\"rd-card\">\n      <div class=\"rd-title\">Meinung äußern</div>\n      <div class=\"rd-phrase\">„Ich bin der Meinung, dass …\"</div>\n      <div class=\"rd-phrase\">„Meiner Ansicht nach …\"</div>\n      <div class=\"rd-phrase\">„Ich finde / halte es für wichtig, dass …\"</div>\n      <div class=\"rd-phrase\">„Ich bin davon überzeugt, dass …\"</div>\n      <div class=\"rd-phrase\">„Aus meiner Sicht …\"</div>\n    </div>\n    <div class=\"rd-card\">\n      <div class=\"rd-title\">Zustimmen &amp; Widersprechen</div>\n      <div class=\"rd-phrase\">„Da stimme ich Ihnen / dir zu.\"</div>\n      <div class=\"rd-phrase\">„Das sehe ich genauso.\"</div>\n      <div class=\"rd-phrase\">„Da bin ich anderer Meinung.\"</div>\n      <div class=\"rd-phrase\">„Das stimmt zwar, aber …\"</div>\n      <div class=\"rd-phrase\">„Ich würde das etwas differenzierter sehen.\"</div>\n    </div>\n    <div class=\"rd-card\">\n      <div class=\"rd-title\">Begründen &amp; Argumentieren</div>\n      <div class=\"rd-phrase\">„Das liegt daran, dass …\"</div>\n      <div class=\"rd-phrase\">„Ein Grund dafür ist …\"</div>\n      <div class=\"rd-phrase\">„Außerdem / Darüber hinaus …\"</div>\n      <div class=\"rd-phrase\">„Einerseits … andererseits …\"</div>\n      <div class=\"rd-phrase\">„Zum Beispiel … / Ein Beispiel dafür ist …\"</div>\n    </div>\n    <div class=\"rd-card\">\n      <div class=\"rd-title\">Abschließen &amp; Zusammenfassen</div>\n      <div class=\"rd-phrase\">„Zusammenfassend lässt sich sagen, dass …\"</div>\n      <div class=\"rd-phrase\">„Alles in allem bin ich der Meinung …\"</div>\n      <div class=\"rd-phrase\">„Abschließend möchte ich betonen …\"</div>\n      <div class=\"rd-phrase\">„Das Wichtigste ist meiner Meinung nach …\"</div>\n      <div class=\"rd-phrase\">„Ich komme daher zu dem Schluss, dass …\"</div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ GROSSE VERGLEICHSTABELLE ════════════════════ -->\n  <div class=\"section-header\"><h2>Alle Prüfungen im Vergleich</h2></div>\n\n  <table class=\"big-table\">\n    <thead>\n      <tr>\n        <th>Prüfung</th>\n        <th>Niveaus</th>\n        <th>Dauer gesamt</th>\n        <th>Besonderheit</th>\n        <th>Wofür anerkannt</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td><strong style=\"color:var(--goethe)\">Goethe-Zertifikat</strong></td>\n        <td>A1 – C2</td>\n        <td>80 – 205 Min. je nach Niveau</td>\n        <td>Modular, 4 Teile einzeln bestehbar; international sehr weit verbreitet</td>\n        <td>Visum, Aufenthaltstitel (AT/DE), Studium, Beruf, Einbürgerung (CH)</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--telc)\">telc Deutsch</strong></td>\n        <td>A1 – C1</td>\n        <td>90 – 210 Min. je nach Niveau</td>\n        <td>Sprachbausteine als Extra-Teil; Berufssprachen-Varianten (Pflege, Medizin)</td>\n        <td>BAMF-Integration, Berufsanerkennung, Behörden DE/AT</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--oesd)\">ÖSD Zertifikat</strong></td>\n        <td>A1 – C2</td>\n        <td>100 – 185 Min. je nach Niveau</td>\n        <td>Schriftlich und mündlich getrennt zertifizierbar; österreichisches Standarddeutsch</td>\n        <td>Aufenthaltstitel AT, Studium AT/DE, international anerkannt</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--dtz)\">DTZ</strong></td>\n        <td>A2 – B1</td>\n        <td>ca. 115 Min.</td>\n        <td>Nur im Rahmen des BAMF-Integrationskurses; Ergebnis: A2 oder B1</td>\n        <td>Niederlassungserlaubnis DE (§ 9 AufenthG), BAMF-Kursnachweis</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--testdaf)\">TestDaF</strong></td>\n        <td>B2 – C1 (TDN 3–5)</td>\n        <td>ca. 3 Std. 15 Min.</td>\n        <td>Kein Prüfer beim Sprechen (Tonaufnahme); bundesweit + international gültig</td>\n        <td>Hochschulzulassung alle deutschen Universitäten; international</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--dsh)\">DSH</strong></td>\n        <td>B2 – C2 (DSH-1/2/3)</td>\n        <td>ca. 3–4 Std. (schriftlich + mündlich)</td>\n        <td>Hochschuleigene Prüfung — Format variiert; meist nur an der ausstellenden HS gültig</td>\n        <td>Hochschulzulassung an der jeweiligen Uni/FH in Deutschland</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- ════════════════════ CHECKLISTE ════════════════════ -->\n  <div class=\"section-header\"><h2>Bin ich prüfungsbereit? — Checkliste</h2></div>\n\n  <div class=\"checklist-grid\">\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kann Aufgaben im Lesen innerhalb der vorgesehenen Zeit lösen — nicht nur verstehen, sondern auch unter Zeitdruck arbeiten.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kann beim Hören Hauptaussage und wichtige Details zuverlässig erfassen und in Stichworten notieren.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kann die Textsorte meines Niveaus strukturiert und vollständig schreiben (Brief, E-Mail, Stellungnahme…).</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kann 2–3 Minuten fließend zu einem Thema sprechen und auf Fragen oder Kommentare reagieren.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kenne den genauen Aufbau meiner Prüfung (Teile, Reihenfolge, Zeiten) — keine Überraschungen am Prüfungstag.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich habe mindestens 2–3 vollständige Probeprüfungen unter echten Bedingungen (Zeitdruck, ohne Hilfsmittel) absolviert.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich habe 20–30 Redemittel für das Sprechen automatisiert — sie kommen ohne Zögern.</span></div>\n    <div class=\"cl-item\"><div class=\"cl-check\"></div><span>Ich kenne die Bestehensregeln meiner Prüfung: welche Mindestpunktzahl pro Teil, was passiert bei Nicht-Bestehen.</span></div>\n  </div>\n\n</div>\n\n<!-- FOOTER -->\n<footer>\n  <p>Offizielle Quellen:\n    <a href=\"https://www.goethe.de/de/spr/kup/prf.html\" target=\"_blank\">Goethe-Institut Prüfungen</a> ·\n    <a href=\"https://www.telc.net\" target=\"_blank\">telc GmbH</a> ·\n    <a href=\"https://www.osd.at\" target=\"_blank\">ÖSD</a> ·\n    <a href=\"https://www.testdaf.de\" target=\"_blank\">TestDaF-Institut</a> ·\n    <a href=\"https://www.bamf.de\" target=\"_blank\">BAMF (DTZ)</a> ·\n    <a href=\"https://www.hochschulkompass.de\" target=\"_blank\">HRK (DSH)</a>\n  </p>\n  <p style=\"margin-top:6px;\">Artikel erstellt 2025 · Alle Angaben nach offiziellen Prüfungsformaten · Für Unterrichtszwecke</p>\n</footer>\n\n<script>\n  function toggleCard(id) {\n    const card = document.getElementById(id);\n    card.classList.toggle('open');\n  }\n  document.getElementById('prov-goethe').classList.add('open');\n</script>\n\n",
    "styles": "\n  .dq-article-document {\n    --bg: #0f0f13;\n    --surface: #17171e;\n    --border: #2a2a38;\n    --text: #e8e6f0;\n    --muted: #8a8aa0;\n    --accent: #5eb8a0;\n    --accent2: #e0a04a;\n\n    --goethe: #5eb8a0;\n    --telc:   #6898d8;\n    --oesd:   #c87050;\n    --dtz:    #a870c8;\n    --testdaf:#58a8c0;\n    --dsh:    #d8784a;\n\n    --a1c:  #6ec6e0;\n    --a2c:  #4db8a8;\n    --b1c:  #7ec86e;\n    --b2c:  #c8b84e;\n    --c1c:  #e07848;\n    --c2c:  #d04870;\n\n    --skill-listen:  #6898d8;\n    --skill-read:    #58b890;\n    --skill-write:   #c8a050;\n    --skill-speak:   #d06878;\n  }\n\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n  .dq-article-document {\n    background: var(--bg);\n    color: var(--text);\n    font-family: 'Source Sans 3', sans-serif;\n    font-weight: 300;\n    line-height: 1.78;\n    min-height: 100vh;\n  }\n\n  /* ── HERO ── */\n  .hero {\n    position: relative;\n    padding: 88px 24px 64px;\n    text-align: center;\n    overflow: hidden;\n  }\n  .hero::before {\n    content: '';\n    position: absolute;\n    inset: 0;\n    background:\n      radial-gradient(ellipse 75% 55% at 50% 0%, rgba(94,184,160,0.13) 0%, transparent 68%),\n      radial-gradient(ellipse 45% 38% at 85% 75%, rgba(104,152,216,0.09) 0%, transparent 58%),\n      radial-gradient(ellipse 40% 30% at 12% 85%, rgba(208,72,120,0.07) 0%, transparent 55%);\n    pointer-events: none;\n  }\n  .hero-eyebrow {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.24em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 18px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.1s forwards;\n  }\n  .hero h1 {\n    font-family: 'Playfair Display', serif;\n    font-size: clamp(2.3rem, 5.5vw, 4.6rem);\n    font-weight: 900;\n    line-height: 1.08;\n    margin-bottom: 22px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.25s forwards;\n  }\n  .hero h1 em { font-style: normal; color: var(--accent); }\n  .hero-sub {\n    max-width: 660px;\n    margin: 0 auto 44px;\n    color: var(--muted);\n    font-size: 1.06rem;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.4s forwards;\n  }\n\n  /* ── PROVIDER PILLS ── */\n  .provider-strip {\n    display: flex;\n    justify-content: center;\n    flex-wrap: wrap;\n    gap: 7px;\n    margin-bottom: 10px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.55s forwards;\n  }\n  .prov-pill {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    font-weight: 600;\n    padding: 4px 13px;\n    border-radius: 20px;\n    border: 1.5px solid currentColor;\n  }\n  .pill-goethe  { color: var(--goethe); }\n  .pill-telc    { color: var(--telc); }\n  .pill-oesd    { color: var(--oesd); }\n  .pill-dtz     { color: var(--dtz); }\n  .pill-testdaf { color: var(--testdaf); }\n  .pill-dsh     { color: var(--dsh); }\n\n  .hero-sub2 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.16em;\n    color: var(--muted);\n    text-align: center;\n    margin-bottom: 0;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.65s forwards;\n  }\n\n  /* ── 4-SKILL BAR ── */\n  .skill-overview {\n    max-width: 880px;\n    margin: 0 auto;\n    padding: 36px 24px 0;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.75s forwards;\n  }\n  .skill-bar-row {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 1px;\n    background: var(--border);\n    border: 1px solid var(--border);\n    border-radius: 14px;\n    overflow: hidden;\n    margin-bottom: 52px;\n  }\n  @media (max-width: 580px) { .skill-bar-row { grid-template-columns: 1fr 1fr; } }\n  .skill-cell {\n    background: var(--surface);\n    padding: 22px 16px;\n    text-align: center;\n  }\n  .skill-icon { font-size: 28px; margin-bottom: 8px; }\n  .skill-name {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.15em;\n    text-transform: uppercase;\n    margin-bottom: 5px;\n  }\n  .skill-name.s-listen { color: var(--skill-listen); }\n  .skill-name.s-read   { color: var(--skill-read); }\n  .skill-name.s-write  { color: var(--skill-write); }\n  .skill-name.s-speak  { color: var(--skill-speak); }\n  .skill-desc { font-size: 0.82rem; color: var(--muted); line-height: 1.5; }\n\n  /* ── MAIN CONTAINER ── */\n  .container {\n    max-width: 900px;\n    margin: 0 auto;\n    padding: 0 24px 88px;\n  }\n\n  /* ── SECTION HEADER ── */\n  .section-header {\n    display: flex;\n    align-items: center;\n    gap: 16px;\n    margin: 60px 0 30px;\n  }\n  .section-header::after {\n    content: '';\n    flex: 1;\n    height: 1px;\n    background: var(--border);\n  }\n  .section-header h2 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.2em;\n    text-transform: uppercase;\n    color: var(--muted);\n    white-space: nowrap;\n  }\n\n  /* ── PROVIDER CARD ── */\n  .prov-card {\n    border: 1px solid var(--border);\n    border-radius: 16px;\n    overflow: hidden;\n    margin-bottom: 24px;\n    opacity: 0;\n    animation: fadeUp 0.5s ease forwards;\n    transition: border-color 0.25s;\n  }\n  .prov-card:nth-child(1) { animation-delay: 0.05s; }\n  .prov-card:nth-child(2) { animation-delay: 0.12s; }\n  .prov-card:nth-child(3) { animation-delay: 0.19s; }\n  .prov-card:nth-child(4) { animation-delay: 0.26s; }\n  .prov-card:nth-child(5) { animation-delay: 0.33s; }\n  .prov-card:nth-child(6) { animation-delay: 0.40s; }\n\n  .prov-header {\n    display: grid;\n    grid-template-columns: auto 1fr auto;\n    align-items: center;\n    gap: 20px;\n    padding: 24px 28px 20px;\n    cursor: pointer;\n    user-select: none;\n  }\n  .prov-logo {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.5rem;\n    font-weight: 900;\n    width: 64px;\n    text-align: center;\n    line-height: 1;\n  }\n  .prov-title {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.28rem;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 4px;\n  }\n  .prov-subtitle { font-size: 0.86rem; color: var(--muted); }\n  .prov-toggle {\n    font-size: 22px;\n    color: var(--muted);\n    transition: transform 0.3s;\n    line-height: 1;\n  }\n  .prov-card.open .prov-toggle { transform: rotate(180deg); }\n\n  .prov-.dq-article-document {\n    padding: 0 28px;\n    max-height: 0;\n    overflow: hidden;\n    transition: max-height 0.5s ease, padding 0.3s ease;\n  }\n  .prov-card.open .prov-.dq-article-document {\n    max-height: 4000px;\n    padding-bottom: 28px;\n  }\n\n  /* ── DESCRIPTION ── */\n  .prov-description {\n    font-size: 0.96rem;\n    color: var(--muted);\n    margin-bottom: 22px;\n    line-height: 1.82;\n    padding: 15px 18px;\n    background: rgba(255,255,255,0.025);\n    border-radius: 10px;\n    border-left: 3px solid currentColor;\n  }\n\n  /* ── GRID ── */\n  .prov-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 18px;\n    margin-bottom: 18px;\n  }\n  @media (max-width: 640px) {\n    .prov-grid { grid-template-columns: 1fr; }\n    .prov-header { gap: 12px; padding: 20px 20px 18px; }\n    .prov-.dq-article-document { padding: 0 20px; }\n    .prov-card.open .prov-.dq-article-document { padding-bottom: 20px; }\n  }\n\n  .p-block {\n    background: var(--surface);\n    border-radius: 10px;\n    padding: 16px 18px;\n  }\n  .p-block h4 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 12px;\n  }\n  .p-block ul {\n    list-style: none;\n    display: flex;\n    flex-direction: column;\n    gap: 7px;\n  }\n  .p-block ul li {\n    font-size: 0.9rem;\n    padding-left: 18px;\n    position: relative;\n    color: var(--text);\n    line-height: 1.6;\n  }\n  .p-block ul li::before {\n    content: '→';\n    position: absolute;\n    left: 0;\n    font-size: 0.75rem;\n    top: 2px;\n  }\n  .p-block-full { grid-column: 1 / -1; }\n\n  /* ── LEVEL TABLE ── */\n  .level-table {\n    width: 100%;\n    border-collapse: collapse;\n    font-size: 0.86rem;\n  }\n  .level-table th {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 9.5px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--muted);\n    text-align: left;\n    padding: 10px 12px;\n    border-bottom: 1px solid var(--border);\n    background: rgba(255,255,255,0.02);\n  }\n  .level-table td {\n    padding: 10px 12px;\n    border-bottom: 1px solid var(--border);\n    vertical-align: top;\n    line-height: 1.5;\n  }\n  .level-table tr:last-child td { border-bottom: none; }\n  .level-table tr:hover td { background: rgba(255,255,255,0.02); }\n\n  /* ── EXAM STRUCTURE BOX ── */\n  .exam-structure {\n    background: var(--surface);\n    border-radius: 12px;\n    overflow: hidden;\n    margin-bottom: 18px;\n  }\n  .exam-structure-title {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--muted);\n    padding: 12px 18px 10px;\n    border-bottom: 1px solid var(--border);\n  }\n  .exam-parts {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 1px;\n    background: var(--border);\n  }\n  @media (max-width: 560px) { .exam-parts { grid-template-columns: 1fr 1fr; } }\n  .exam-part {\n    background: var(--surface);\n    padding: 14px 12px;\n    text-align: center;\n  }\n  .ep-name {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.12em;\n    text-transform: uppercase;\n    margin-bottom: 5px;\n  }\n  .ep-time {\n    font-size: 1.15rem;\n    font-family: 'Playfair Display', serif;\n    font-weight: 700;\n    margin-bottom: 3px;\n  }\n  .ep-detail { font-size: 0.76rem; color: var(--muted); line-height: 1.45; }\n\n  /* ── TAGS ── */\n  .tags {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 7px;\n  }\n  .tag {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    padding: 3px 10px;\n    border-radius: 6px;\n    background: rgba(255,255,255,0.05);\n    border: 1px solid var(--border);\n    color: var(--muted);\n  }\n\n  /* ── NOTICE / FACT ── */\n  .notice {\n    background: rgba(94,184,160,0.07);\n    border: 1px solid rgba(94,184,160,0.2);\n    border-radius: 10px;\n    padding: 15px 20px;\n    font-size: 0.88rem;\n    color: var(--muted);\n    margin-bottom: 18px;\n    line-height: 1.72;\n  }\n  .notice strong { color: var(--accent); }\n\n  .warn-box {\n    background: rgba(224,160,74,0.07);\n    border: 1px solid rgba(224,160,74,0.2);\n    border-radius: 10px;\n    padding: 15px 20px;\n    font-size: 0.88rem;\n    color: var(--muted);\n    margin-bottom: 18px;\n    line-height: 1.72;\n  }\n  .warn-box strong { color: var(--accent2); }\n\n  /* ── PROVIDER COLORS ── */\n  .lv-goethe  { color: var(--goethe); border-color: rgba(94,184,160,0.22); }\n  .lv-telc    { color: var(--telc);   border-color: rgba(104,152,216,0.22); }\n  .lv-oesd    { color: var(--oesd);   border-color: rgba(200,112,80,0.22); }\n  .lv-dtz     { color: var(--dtz);    border-color: rgba(168,112,200,0.22); }\n  .lv-testdaf { color: var(--testdaf);border-color: rgba(88,168,192,0.22); }\n  .lv-dsh     { color: var(--dsh);    border-color: rgba(216,120,74,0.22); }\n\n  .prov-card.lv-goethe:hover  { border-color: var(--goethe); }\n  .prov-card.lv-telc:hover    { border-color: var(--telc); }\n  .prov-card.lv-oesd:hover    { border-color: var(--oesd); }\n  .prov-card.lv-dtz:hover     { border-color: var(--dtz); }\n  .prov-card.lv-testdaf:hover { border-color: var(--testdaf); }\n  .prov-card.lv-dsh:hover     { border-color: var(--dsh); }\n\n  .prov-description.lv-goethe  { border-color: var(--goethe); }\n  .prov-description.lv-telc    { border-color: var(--telc); }\n  .prov-description.lv-oesd    { border-color: var(--oesd); }\n  .prov-description.lv-dtz     { border-color: var(--dtz); }\n  .prov-description.lv-testdaf { border-color: var(--testdaf); }\n  .prov-description.lv-dsh     { border-color: var(--dsh); }\n\n  /* ── EXAM DAY TIMELINE ── */\n  .day-timeline {\n    display: flex;\n    flex-direction: column;\n    gap: 0;\n    margin-bottom: 18px;\n  }\n  .dt-step {\n    display: grid;\n    grid-template-columns: 52px 1fr;\n    gap: 16px;\n    align-items: stretch;\n  }\n  .dt-left {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n  }\n  .dt-dot {\n    width: 14px;\n    height: 14px;\n    border-radius: 50%;\n    border: 2px solid var(--accent);\n    background: var(--bg);\n    flex-shrink: 0;\n    margin-top: 4px;\n  }\n  .dt-line {\n    width: 2px;\n    flex: 1;\n    background: var(--border);\n    margin: 4px 0;\n    min-height: 20px;\n  }\n  .dt-step:last-child .dt-line { display: none; }\n  .dt-content {\n    padding-bottom: 18px;\n  }\n  .dt-time {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.12em;\n    color: var(--accent);\n    margin-bottom: 3px;\n    text-transform: uppercase;\n  }\n  .dt-title {\n    font-weight: 600;\n    font-size: 0.95rem;\n    margin-bottom: 4px;\n  }\n  .dt-desc { font-size: 0.86rem; color: var(--muted); line-height: 1.6; }\n\n  /* ── SKILL TRAINING CARDS ── */\n  .training-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 16px;\n    margin-bottom: 24px;\n  }\n  @media (max-width: 600px) { .training-grid { grid-template-columns: 1fr; } }\n  .tr-card {\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    padding: 20px;\n    border-top: 3px solid currentColor;\n  }\n  .tr-card.s-listen { color: var(--skill-listen); }\n  .tr-card.s-read   { color: var(--skill-read); }\n  .tr-card.s-write  { color: var(--skill-write); }\n  .tr-card.s-speak  { color: var(--skill-speak); }\n  .tr-icon { font-size: 22px; margin-bottom: 8px; }\n  .tr-title {\n    font-family: 'Source Sans 3', sans-serif;\n    font-weight: 600;\n    font-size: 0.97rem;\n    color: var(--text);\n    margin-bottom: 8px;\n  }\n  .tr-.dq-article-document { font-size: 0.86rem; color: var(--muted); line-height: 1.65; }\n  .tr-.dq-article-document ul { list-style: none; padding: 0; }\n  .tr-.dq-article-document ul li {\n    padding-left: 16px;\n    position: relative;\n    margin-bottom: 5px;\n  }\n  .tr-.dq-article-document ul li::before {\n    content: '·';\n    position: absolute;\n    left: 4px;\n  }\n\n  /* ── CHECKLIST ── */\n  .checklist-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 12px;\n    margin-bottom: 24px;\n  }\n  @media (max-width: 580px) { .checklist-grid { grid-template-columns: 1fr; } }\n  .cl-item {\n    display: flex;\n    align-items: flex-start;\n    gap: 12px;\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 10px;\n    padding: 14px 16px;\n    font-size: 0.88rem;\n    line-height: 1.55;\n    color: var(--text);\n  }\n  .cl-check {\n    width: 22px;\n    height: 22px;\n    border: 1.5px solid var(--border);\n    border-radius: 5px;\n    flex-shrink: 0;\n    margin-top: 1px;\n  }\n\n  /* ── COMPARISON TABLE (BIG) ── */\n  .big-table {\n    width: 100%;\n    border-collapse: collapse;\n    font-size: 0.85rem;\n    margin-bottom: 28px;\n  }\n  .big-table th {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--muted);\n    text-align: left;\n    padding: 12px 14px;\n    border-bottom: 1px solid var(--border);\n    background: var(--surface);\n    white-space: nowrap;\n  }\n  .big-table td {\n    padding: 11px 14px;\n    border-bottom: 1px solid var(--border);\n    vertical-align: top;\n    line-height: 1.5;\n  }\n  .big-table tr:last-child td { border-bottom: none; }\n  .big-table tr:hover td { background: rgba(255,255,255,0.02); }\n\n  /* ── REDEMITTEL BOX ── */\n  .redemittel-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 16px;\n    margin-bottom: 24px;\n  }\n  @media (max-width: 580px) { .redemittel-grid { grid-template-columns: 1fr; } }\n  .rd-card {\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 10px;\n    padding: 16px 18px;\n  }\n  .rd-title {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 10px;\n  }\n  .rd-phrase {\n    font-family: 'Playfair Display', serif;\n    font-style: italic;\n    font-size: 0.9rem;\n    color: var(--text);\n    padding: 5px 0;\n    border-bottom: 1px solid var(--border);\n    line-height: 1.55;\n  }\n  .rd-phrase:last-child { border-bottom: none; }\n\n  /* ── FOOTER ── */\n  footer {\n    border-top: 1px solid var(--border);\n    padding: 34px 24px;\n    text-align: center;\n    color: var(--muted);\n    font-size: 0.83rem;\n    line-height: 1.8;\n  }\n  footer a { color: var(--accent); text-decoration: none; }\n  footer a:hover { text-decoration: underline; }\n\n  /* ── ANIMATIONS ── */\n  @keyframes fadeUp {\n    from { opacity: 0; transform: translateY(18px); }\n    to   { opacity: 1; transform: translateY(0); }\n  }\n\n  /* ── SCORE BAR ── */\n  .score-row {\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    margin-bottom: 8px;\n    font-size: 0.86rem;\n  }\n  .score-label {\n    width: 90px;\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    color: var(--muted);\n    flex-shrink: 0;\n  }\n  .score-track {\n    flex: 1;\n    height: 6px;\n    background: var(--border);\n    border-radius: 3px;\n    overflow: hidden;\n  }\n  .score-fill {\n    height: 100%;\n    border-radius: 3px;\n    background: var(--accent);\n  }\n  .score-val {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    color: var(--muted);\n    width: 40px;\n    text-align: right;\n    flex-shrink: 0;\n  }\n"
  },
  "sprachniveaus-a1-c1": {
    "content": "\n\n<!-- ════════════════════ HERO ════════════════════ -->\n<header class=\"hero\">\n  <p class=\"hero-eyebrow\">GER / CEFR · Gemeinsamer Europäischer Referenzrahmen</p>\n  <h1>Lernweg Deutsch:<br><em>A0 bis C2</em></h1>\n  <p class=\"hero-sub\">Vollständige Beschreibung jeder Niveaustufe — was Sie können, welche Grammatik Sie brauchen, wie lange das Lernen dauert und welche Prüfungen Ihr Niveau bestätigen.</p>\n\n  <div class=\"level-strip\">\n    <span class=\"level-pill pill-a0\">A0</span>\n    <span class=\"level-pill pill-a1\">A1</span>\n    <span class=\"level-pill pill-a2\">A2</span>\n    <span class=\"level-pill pill-b1\">B1</span>\n    <span class=\"level-pill pill-b2\">B2</span>\n    <span class=\"level-pill pill-c1\">C1</span>\n    <span class=\"level-pill pill-c2\">C2</span>\n  </div>\n  <p class=\"group-label\">Elementar · Selbstständig · Kompetent</p>\n</header>\n\n<!-- ════════════════════ CEFR OVERVIEW ════════════════════ -->\n<div class=\"container\" style=\"max-width:860px; padding-bottom:0;\">\n  <div class=\"cefr-bar\">\n    <div class=\"cefr-group elementary\">\n      <p class=\"cefr-group-label\">A1 – A2</p>\n      <p class=\"cefr-group-title\">Elementare Verwendung</p>\n      <p class=\"cefr-group-sub\">Grundlegende Kommunikationsfähigkeit für den Alltag</p>\n    </div>\n    <div class=\"cefr-group independent\">\n      <p class=\"cefr-group-label\">B1 – B2</p>\n      <p class=\"cefr-group-title\">Selbstständige Verwendung</p>\n      <p class=\"cefr-group-sub\">Eigenständige Kommunikation in Beruf, Studium und Gesellschaft</p>\n    </div>\n    <div class=\"cefr-group proficient\">\n      <p class=\"cefr-group-label\">C1 – C2</p>\n      <p class=\"cefr-group-title\">Kompetente Verwendung</p>\n      <p class=\"cefr-group-sub\">Freies, präzises Sprachhandeln auf akademischem und beruflichem Spitzenniveau</p>\n    </div>\n  </div>\n\n  <div class=\"progress-track\">\n    <div class=\"progress-bar\">\n      <div class=\"pb-seg pb-a0\"></div>\n      <div class=\"pb-seg pb-a1\"></div>\n      <div class=\"pb-seg pb-a2\"></div>\n      <div class=\"pb-seg pb-b1\"></div>\n      <div class=\"pb-seg pb-b2\"></div>\n      <div class=\"pb-seg pb-c1\"></div>\n      <div class=\"pb-seg pb-c2\"></div>\n    </div>\n    <div class=\"progress-labels\">\n      <span>A0</span><span>A1</span><span>A2</span><span>B1</span><span>B2</span><span>C1</span><span>C2</span>\n    </div>\n  </div>\n</div>\n\n<!-- ════════════════════ LEVEL CARDS ════════════════════ -->\n<div class=\"container\">\n\n  <div class=\"section-header\"><h2>Niveaustufen im Detail</h2></div>\n\n  <!-- ─── A0 ─── -->\n  <div class=\"level-card lv-a0\" id=\"lv-a0\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-a0')\">\n      <div class=\"level-badge\">A0</div>\n      <div>\n        <p class=\"card-title\">Vorstufe / Einstieg</p>\n        <p class=\"card-subtitle\">Pre-A1 · „Ich bin neu\" · Erste Wörter und Phrasen</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <p class=\"card-description lv-a0\">\n        A0 ist keine offizielle Stufe des GER/CEFR – sie beschreibt den Zustand <strong>vor dem Einstieg</strong> in das System. Auf diesem Niveau haben Sie noch keine aktive Sprachkompetenz, aber Sie können erste Wörter, das Alphabet und einfache Begrüßungen aufnehmen. Viele Sprachschulen verwenden A0 als praktischen Startpunkt, um den Übergang zu A1 strukturiert zu gestalten. Das Ziel ist einfach: erste Hemmungen abbauen, sich mit Klang und Rhythmus des Deutschen vertraut machen und ein solides Fundament für A1 legen.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie bereits können</h4>\n          <ul>\n            <li>Sehr einfache Wörter verstehen: Hallo, Danke, Ja, Nein, Bitte</li>\n            <li>Sich mit wenigen Wörtern vorstellen: Name, Herkunftsland</li>\n            <li>Das Alphabet buchstabieren: M-A-X</li>\n            <li>Zahlen von 1 bis 20 nennen</li>\n            <li>Grundlegende Farben und Wochentage kennen</li>\n            <li>Einfache Schilder und Aufschriften lesen (Eingang, Ausgang, WC)</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Begrüßung und Verabschiedung</li>\n            <li>Name, Alter, Herkunftsland</li>\n            <li>Zahlen 1–100, Farben</li>\n            <li>Wochentage und Monate</li>\n            <li>Einfache Orte: Bahnhof, Schule, Café, Supermarkt</li>\n            <li>Höfliche Grundformeln: Entschuldigung, Wie bitte?</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Erste Grammatikbausteine</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Artikel: der / die / das</span>\n            <span class=\"grammar-tag\">Personalpronomen: ich, du, er, sie, es</span>\n            <span class=\"grammar-tag\">Präsens von sein und haben</span>\n            <span class=\"grammar-tag\">Basisverben: heißen, kommen, wohnen</span>\n            <span class=\"grammar-tag\">W-Fragen: Wie? Woher? Was?</span>\n            <span class=\"grammar-tag\">Zahlen 1–100</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann meinen Namen auf Deutsch buchstabieren.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann sagen: „Ich heiße … / Ich komme aus …\"</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kenne die Zahlen von 1 bis 20.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich verstehe einfache Begrüßungen und kann sie erwidern.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-a0\">„Hallo! Ich heiße Lina. Ich komme aus der Ukraine.\"</div>\n          <div class=\"example-item lv-a0\">„Mein Name ist Max. Ich bin zwanzig Jahre alt.\"</div>\n          <div class=\"example-item lv-a0\">„Entschuldigung! Wie bitte?\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 0 – 60 Unterrichtsstunden</div>\n    </div>\n  </div>\n\n  <!-- ─── A1 ─── -->\n  <div class=\"level-card lv-a1\" id=\"lv-a1\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-a1')\">\n      <div class=\"level-badge\">A1</div>\n      <div>\n        <p class=\"card-title\">Elementare Sprachverwendung</p>\n        <p class=\"card-subtitle\">„Überleben im Alltag\" · Erste offizielle GER/CEFR-Stufe</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <p class=\"card-description lv-a1\">\n        Auf A1 können Sie sich in <strong>einfachen, vertrauten Alltagssituationen</strong> verständigen, sofern Ihr Gesprächspartner langsam und deutlich spricht und bereit ist, zu helfen. Sie verstehen und benutzen sehr geläufige Ausdrücke und ganz einfache Sätze. Das Ziel ist nicht Perfektion, sondern funktionale Kommunikation: im Café bestellen, nach dem Weg fragen, sich vorstellen. Auf A1 lernt man, Deutsch als Überlebensinstrument im Alltag einzusetzen.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>Sich vorstellen und einfache persönliche Fragen stellen und beantworten</li>\n            <li>Im Café oder Restaurant bestellen und bezahlen</li>\n            <li>Nach dem Weg fragen und einfache Wegbeschreibungen verstehen</li>\n            <li>Einfache Formulare ausfüllen (Name, Adresse, Geburtsdatum)</li>\n            <li>Kurze Ansagen verstehen, wenn langsam und deutlich gesprochen wird</li>\n            <li>Über Familie, Beruf und Wohnort sprechen</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Familie und Freunde</li>\n            <li>Wohnung, Haus, Zimmer</li>\n            <li>Essen, Trinken, Einkaufen</li>\n            <li>Uhrzeit, Tagesablauf, Wochentage</li>\n            <li>Berufe und Hobbys</li>\n            <li>Stadtteile, Verkehrsmittel</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Grammatik auf diesem Niveau</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Präsens – regelmäßige Verben</span>\n            <span class=\"grammar-tag\">Modalverben: können, müssen, wollen, möchten</span>\n            <span class=\"grammar-tag\">Negation: nicht / kein</span>\n            <span class=\"grammar-tag\">Nominativ &amp; Akkusativ</span>\n            <span class=\"grammar-tag\">Trennbare Verben (erste)</span>\n            <span class=\"grammar-tag\">W-Fragen + Ja-/Nein-Fragen</span>\n            <span class=\"grammar-tag\">Possessivpronomen: mein, dein, sein</span>\n            <span class=\"grammar-tag\">Plural der Nomen (häufigste Formen)</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann im Café einen Kaffee und die Rechnung bestellen.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann nach dem Weg zur U-Bahn fragen.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich verstehe, wenn jemand langsam und deutlich mit mir spricht.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann einfache Angaben zu meiner Person machen.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-a1\">„Ich hätte gern einen Kaffee und ein Croissant, bitte. Und die Rechnung, bitte.\"</div>\n          <div class=\"example-item lv-a1\">„Entschuldigung, wo ist die nächste U-Bahn-Station?\"</div>\n          <div class=\"example-item lv-a1\">„Ich wohne in Wien. Ich arbeite als Lehrerin. Ich habe zwei Kinder.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 60 – 160 Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ─── A2 ─── -->\n  <div class=\"level-card lv-a2\" id=\"lv-a2\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-a2')\">\n      <div class=\"level-badge\">A2</div>\n      <div>\n        <p class=\"card-title\">Sicherer Alltag</p>\n        <p class=\"card-subtitle\">„Alltag sicher erklären\" · Routinesituationen ohne Stress</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <p class=\"card-description lv-a2\">\n        Auf A2 können Sie sich in <strong>routinemäßigen Alltagssituationen</strong> verständigen und über vertraute Themen sprechen oder schreiben. Sie sind in der Lage, einfache Informationen über sich und Ihre Umgebung auszutauschen. Anders als auf A1 können Sie jetzt auch über <strong>Vergangenes berichten</strong>, Termine vereinbaren und einfache Gründe nennen. A2 ist der erste Schritt zur sprachlichen Selbstständigkeit im deutschsprachigen Alltag.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>Alltagssituationen bewältigen: Arzttermin, Bank, Supermarkt, Behörden (einfach)</li>\n            <li>Kurz erzählen, was gestern oder letzte Woche passiert ist</li>\n            <li>Einen Termin telefonisch vereinbaren oder absagen</li>\n            <li>Einfache SMS, Notizen oder kurze E-Mails schreiben</li>\n            <li>Einfache Gründe nennen und verknüpfen: „weil …\", „deshalb …\"</li>\n            <li>Kurze Ankündigungen, Schilder und Menüs verstehen</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Gesundheit, Arztbesuch, Apotheke</li>\n            <li>Arbeit, Kollegen, Büro</li>\n            <li>Feste, Traditionen, Jahreszeiten</li>\n            <li>Wochenendpläne und Freizeitaktivitäten</li>\n            <li>Einfache Beschwerden und Bitten</li>\n            <li>Reisen, Unterkunft, Ausflüge</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Grammatik auf diesem Niveau</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Perfekt (Hauptvergangenheit)</span>\n            <span class=\"grammar-tag\">Akkusativ &amp; Dativ (sicher)</span>\n            <span class=\"grammar-tag\">Trennbare und untrennbare Verben</span>\n            <span class=\"grammar-tag\">Nebensätze: weil, dass, wenn</span>\n            <span class=\"grammar-tag\">Vergleiche: größer als / am besten</span>\n            <span class=\"grammar-tag\">Präpositionen mit Dativ und Akkusativ</span>\n            <span class=\"grammar-tag\">Imperativ (Aufforderungen)</span>\n            <span class=\"grammar-tag\">Zeitangaben: damals, gestern, nächste Woche</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann beim Arzt einen Termin telefonisch vereinbaren.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann erzählen, was ich gestern gemacht habe.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich verstehe einfache Briefe und Aushänge.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann einen Termin verschieben oder absagen.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-a2\">„Ich habe gestern beim Arzt angerufen, weil ich Halsschmerzen habe.\"</div>\n          <div class=\"example-item lv-a2\">„Können wir den Termin auf Donnerstagnachmittag verschieben?\"</div>\n          <div class=\"example-item lv-a2\">„Ich stehe um sieben Uhr auf und fahre mit der U-Bahn zur Arbeit.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 160 – 350 Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ─── B1 ─── -->\n  <div class=\"level-card lv-b1\" id=\"lv-b1\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-b1')\">\n      <div class=\"level-badge\">B1</div>\n      <div>\n        <p class=\"card-title\">Selbstständiges Sprechen</p>\n        <p class=\"card-subtitle\">„Zusammenhängend sprechen\" · Mindestanforderung für Aufenthalt &amp; Arbeit</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <div class=\"notice\"><strong>⚡ Wichtig:</strong> B1 ist das <strong>gesetzliche Mindesterfordernis</strong> für den dauerhaften Aufenthalt in Österreich (Niederlassungsbewilligung) und Deutschland (Niederlassungserlaubnis). In der Schweiz ist B1 Voraussetzung für die Einbürgerung. Auch für viele Ausbildungsberufe und die Anerkennung ausländischer Abschlüsse wird B1 verlangt.</div>\n      <p class=\"card-description lv-b1\">\n        Auf B1 verstehen Sie die <strong>Hauptaussagen klarer Standardsprache</strong> zu vertrauten Themen aus Alltag, Schule und Beruf. Sie können die meisten Situationen bewältigen, die beim Reisen in einem deutschsprachigen Land entstehen. Sie können sich einfach und zusammenhängend zu vertrauten Themen äußern und über Erfahrungen, Ereignisse, Träume und Ziele berichten und kurze Begründungen oder Erklärungen geben. B1 bedeutet: Sie kommunizieren nicht mehr nur reaktiv – Sie <em>gestalten</em> aktiv Gespräche.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>Über Erfahrungen, Pläne und Wünsche zusammenhängend sprechen</li>\n            <li>Eine einfache Meinung äußern und kurz begründen</li>\n            <li>Längere Alltagsgespräche führen – nicht perfekt, aber stabil</li>\n            <li>E-Mails, Beschwerden und kurze Bewerbungen schreiben</li>\n            <li>Den Inhalt von Radionachrichten und einfachen Podcasts verstehen</li>\n            <li>Texte zu vertrauten Themen lesen und den Hauptgedanken erfassen</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Ausbildung, Studium, Berufseinstieg</li>\n            <li>Gesellschaft, Umwelt, Medien</li>\n            <li>Kultur, Reisen, Sport, Freizeit</li>\n            <li>Probleme und Lösungen im Alltag</li>\n            <li>Offizielle Briefe und Anträge</li>\n            <li>Persönliche Träume und Lebenspläne</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Grammatik auf diesem Niveau</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Präteritum (sein, haben, Modalverben)</span>\n            <span class=\"grammar-tag\">Nebensätze: obwohl, damit, während, als, bevor</span>\n            <span class=\"grammar-tag\">Infinitiv mit zu</span>\n            <span class=\"grammar-tag\">Konjunktiv II (hätte, wäre, würde) – Grundlagen</span>\n            <span class=\"grammar-tag\">Relativsätze (Nominativ / Akkusativ)</span>\n            <span class=\"grammar-tag\">Passiv Präsens – erste Einführung</span>\n            <span class=\"grammar-tag\">Erste feste Redewendungen</span>\n            <span class=\"grammar-tag\">Indirekte Fragen: Ich weiß nicht, ob …</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann 2–3 Minuten frei über ein Thema sprechen.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann eine E-Mail schreiben, in der ich um Hilfe bitte.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich verstehe den Kern von Radionachrichten zu vertrauten Themen.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann meine Meinung äußern und einfach begründen.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-b1\">„Ich war letzten Sommer in München. Es hat mir sehr gut gefallen, obwohl es ziemlich teuer war.\"</div>\n          <div class=\"example-item lv-b1\">„Ich denke, dass Deutschkenntnisse wichtig sind, weil ich hier langfristig arbeiten möchte.\"</div>\n          <div class=\"example-item lv-b1\">„Ich möchte einen Termin vereinbaren, um das Problem persönlich zu besprechen.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 350 – 600 Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ─── B2 ─── -->\n  <div class=\"level-card lv-b2\" id=\"lv-b2\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-b2')\">\n      <div class=\"level-badge\">B2</div>\n      <div>\n        <p class=\"card-title\">Fließend und flexibel</p>\n        <p class=\"card-subtitle\">„Flüssig und flexibel\" · Sicher in Beruf und Studium</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <div class=\"notice\"><strong>⚡ Wichtig:</strong> B2 ist das <strong>Mindestniveau für die Zulassung zu den meisten Universitäten</strong> in Österreich und Deutschland. Für medizinische Berufe (Ärzte, Pflegepersonal, Apotheker) ist B2 in der Regel die gesetzlich vorgeschriebene Mindestvoraussetzung für die Berufsanerkennung.</div>\n      <p class=\"card-description lv-b2\">\n        Auf B2 verstehen Sie die Hauptinhalte <strong>komplexer Texte zu konkreten und abstrakten Themen</strong>, einschließlich Fachdiskussionen in Ihrem Spezialgebiet. Sie können sich so spontan und fließend verständigen, dass ein normales Gespräch mit einem Muttersprachler ohne größere Anstrengung möglich ist. Sie können sich zu einem breiten Themenspektrum klar und detailliert ausdrücken und einen Standpunkt zu einer aktuellen Frage erläutern sowie Vor- und Nachteile verschiedener Möglichkeiten angeben.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>An Diskussionen teilnehmen und Argumente strukturiert darlegen</li>\n            <li>Berufliche Verhandlungen und Besprechungen sicher führen</li>\n            <li>Klare, detaillierte Texte schreiben: Berichte, Stellungnahmen, Zusammenfassungen</li>\n            <li>Authentische Texte und Rundfunksendungen verstehen</li>\n            <li>Spontan reagieren, ohne sichtbar nach Worten suchen zu müssen</li>\n            <li>Stil und Ton je nach Situation anpassen (formell / informell)</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Wirtschaft, Gesellschaft, aktuelle Politik</li>\n            <li>Wissenschaft und Technologie (zugänglich)</li>\n            <li>Kunst, Film, Literatur, Musik</li>\n            <li>Geschäftskorrespondenz und Berichte</li>\n            <li>Abstrakte Konzepte und Ideen</li>\n            <li>Interkulturelle Fragen und Lebensstile</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Grammatik auf diesem Niveau</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Konjunktiv II (erweitert und sicher)</span>\n            <span class=\"grammar-tag\">Passiv (Präteritum, Perfekt, mit Modalverben)</span>\n            <span class=\"grammar-tag\">Nominalisierung (Verb → Nomen)</span>\n            <span class=\"grammar-tag\">Partizipialkonstruktionen</span>\n            <span class=\"grammar-tag\">Zweiteilige Konnektoren: sowohl … als auch, entweder … oder</span>\n            <span class=\"grammar-tag\">Konjunktiv I (indirekte Rede)</span>\n            <span class=\"grammar-tag\">Stilistische Register: neutral, formell, umgangssprachlich</span>\n            <span class=\"grammar-tag\">Erweiterte Relativsätze (alle Fälle)</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann spontan argumentieren, ohne lange nach Worten zu suchen.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann einen logisch aufgebauten Bericht oder eine Stellungnahme schreiben.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich verstehe die meisten Fernsehsendungen und Zeitungsartikel.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann Vor- und Nachteile eines Themas differenziert darstellen.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-b2\">„Meiner Meinung nach hat diese Maßnahme zwei wesentliche Vorteile, allerdings auch einen erheblichen Nachteil, der nicht unterschätzt werden sollte.\"</div>\n          <div class=\"example-item lv-b2\">„Wenn ich mehr Zeit hätte, würde ich einen intensiveren Kurs belegen und täglich üben.\"</div>\n          <div class=\"example-item lv-b2\">„Das Problem wird in der öffentlichen Diskussion häufig vereinfacht dargestellt.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 600 – 900 Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ─── C1 ─── -->\n  <div class=\"level-card lv-c1\" id=\"lv-c1\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-c1')\">\n      <div class=\"level-badge\">C1</div>\n      <div>\n        <p class=\"card-title\">Akademische und berufliche Kompetenz</p>\n        <p class=\"card-subtitle\">„Sehr sicher im Studium und Beruf\" · Flexibel und treffsicher</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <p class=\"card-description lv-c1\">\n        Auf C1 können Sie ein <strong>breites Spektrum anspruchsvoller, längerer Texte verstehen</strong> und auch implizite Bedeutungen erfassen. Sie drücken sich fließend und spontan aus, ohne öfter merklich nach Worten suchen zu müssen. Sie verwenden die Sprache im gesellschaftlichen und beruflichen Leben oder in Ausbildung und Studium wirksam und flexibel. Sie können sich klar, strukturiert und ausführlich zu komplexen Sachverhalten äußern und dabei verschiedene Mittel zur Textverknüpfung angemessen verwenden. C1 ist das Niveau der <strong>echten sprachlichen Freiheit</strong>: Sie meistern hitzige Diskussionen, schwierige Verhandlungen und anspruchsvolle akademische Texte.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>Implizite Bedeutungen und Zwischentöne verstehen</li>\n            <li>Präsentationen halten und Meetings moderieren</li>\n            <li>Anspruchsvolle Texte strukturieren: Analysen, Essays, Konzepte</li>\n            <li>Stil flexibel anpassen: formal, sachlich, überzeugend, diplomatisch</li>\n            <li>Komplexe akademische Vorlesungen und Fachdiskussionen folgen</li>\n            <li>Literarische und journalistische Texte verstehen und analysieren</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Akademische Texte und Fachartikel</li>\n            <li>Komplexe gesellschaftliche Fragen</li>\n            <li>Juristische und geschäftliche Sprache</li>\n            <li>Öffentliche Debatten und Reden</li>\n            <li>Literarische Prosa und wissenschaftliche Abhandlungen</li>\n            <li>Interkulturelle Kommunikation auf hohem Niveau</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Sprache und Stilmittel auf diesem Niveau</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Nuancierte Konnektoren: nichtsdestotrotz, insofern, währenddessen</span>\n            <span class=\"grammar-tag\">Erweiterte Partizipialkonstruktionen</span>\n            <span class=\"grammar-tag\">Breite stilistische Variation</span>\n            <span class=\"grammar-tag\">Idiomatik und feste Wendungen</span>\n            <span class=\"grammar-tag\">Präzise, differenzierte Wortwahl</span>\n            <span class=\"grammar-tag\">Kohäsionsmittel im Text (Referenz, Substitution, Ellipse)</span>\n            <span class=\"grammar-tag\">Rhetorik: Ironie, Understatement, Litotes</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann ein komplexes Thema 5–10 Minuten frei und strukturiert präsentieren.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Meine Texte wirken auf Muttersprachler professionell und gepflegt.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich erkenne Ironie, Andeutungen und Subtext im Gespräch.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich folge akademischen Vorlesungen ohne größere Schwierigkeiten.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-c1\">„Zusammenfassend lässt sich feststellen, dass die Maßnahme durchaus wirksam ist, sofern die strukturellen Rahmenbedingungen entsprechend angepasst werden.\"</div>\n          <div class=\"example-item lv-c1\">„Ich schlage vor, das weitere Vorgehen in drei klar definierte Phasen zu gliedern, um Transparenz und Effizienz sicherzustellen.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 900 – 1200 Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ─── C2 ─── -->\n  <div class=\"level-card lv-c2\" id=\"lv-c2\">\n    <div class=\"card-header\" onclick=\"toggleCard('lv-c2')\">\n      <div class=\"level-badge\">C2</div>\n      <div>\n        <p class=\"card-title\">Meisterliche Sprachbeherrschung</p>\n        <p class=\"card-subtitle\">„Nahezu wie ein Muttersprachler\" · Funktionale Perfektion</p>\n      </div>\n      <div class=\"card-toggle\">▾</div>\n    </div>\n    <div class=\"card-body\">\n      <p class=\"card-description lv-c2\">\n        C2 ist die höchste Stufe des GER/CEFR. Sie können auf diesem Niveau <strong>praktisch alles, was Sie hören oder lesen, mühelos verstehen</strong>. Sie können Informationen aus verschiedenen schriftlichen und mündlichen Quellen zusammenfassen und dabei Begründungen und Erklärungen in einer zusammenhängenden Darstellung wiedergeben. Sie können sich spontan, sehr flüssig und genau ausdrücken und dabei auch bei komplexeren Sachverhalten feinere Bedeutungsnuancen deutlich machen. C2 ist nicht gleichbedeutend mit dem Niveau eines Muttersprachlers – es beschreibt vielmehr eine <em>funktionale Meisterschaft</em>, die in praktisch allen Kommunikationssituationen trägt.\n      </p>\n      <div class=\"card-grid\">\n        <div class=\"card-block\">\n          <h4>Was Sie können</h4>\n          <ul>\n            <li>Praktisch jeden Text und jede Rede verstehen und zusammenfassen</li>\n            <li>Spontan, flüssig und stilistisch tadellos sprechen</li>\n            <li>Komplexe Inhalte präzise und komprimiert wiedergeben</li>\n            <li>Missverständnisse elegant vermeiden – diplomatisch und präzise</li>\n            <li>Ironie, Wortspiele, Humor und kulturelle Anspielungen erkennen und einsetzen</li>\n            <li>Sich je nach Zielgruppe flexibel ausdrücken (von umgangssprachlich bis hochformell)</li>\n          </ul>\n        </div>\n        <div class=\"card-block\">\n          <h4>Typische Themen</h4>\n          <ul>\n            <li>Jedes Thema – von der Alltagssprache bis zur Wissenschaft</li>\n            <li>Feine gesellschaftliche und kulturelle Phänomene</li>\n            <li>Spezialisierte Fachterminologie in jedem Bereich</li>\n            <li>Rhetorik, Überzeugung, Verhandlung auf höchstem Niveau</li>\n            <li>Literatur, Philosophie, Kunst</li>\n          </ul>\n        </div>\n        <div class=\"card-block card-block-full\">\n          <h4>Merkmale der Sprachkompetenz</h4>\n          <div class=\"grammar-tags\">\n            <span class=\"grammar-tag\">Höchste stilistische Präzision</span>\n            <span class=\"grammar-tag\">Vollständige idiomatische Beherrschung</span>\n            <span class=\"grammar-tag\">Flexible Anpassung an jede Zielgruppe</span>\n            <span class=\"grammar-tag\">Nuancierte, differenzierte Argumentation</span>\n            <span class=\"grammar-tag\">Ironie und Humor (Verständnis &amp; Einsatz)</span>\n            <span class=\"grammar-tag\">Minimale fremdsprachliche Merkmale</span>\n            <span class=\"grammar-tag\">Souveräner Umgang mit Tabuthemen und heiklen Situationen</span>\n          </div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Kleiner Selbsttest</h4>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich kann einen schwierigen Text präzise zusammenfassen, ohne Nuancen zu verlieren.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich finde auch in heiklen Gesprächen die genau passende Formulierung.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Muttersprachler nehmen mich als nahezu gleichwertig wahr.</span></div>\n          <div class=\"selftest-item\"><div class=\"selftest-check\"></div><span>Ich erkenne Ironie, Stil und kulturelle Referenzen ohne Probleme.</span></div>\n        </div>\n        <div class=\"card-block\">\n          <h4>Beispielsätze</h4>\n          <div class=\"example-item lv-c2\">„Der Kernpunkt ist weniger die Maßnahme selbst als die Art und Weise, wie sie kommuniziert, wahrgenommen und letztlich in der öffentlichen Debatte verankert wird.\"</div>\n          <div class=\"example-item lv-c2\">„Gestatten Sie mir, das zu präzisieren: Es geht nicht um X per se, sondern um die systemischen Implikationen, die Y langfristig nach sich zieht.\"</div>\n        </div>\n      </div>\n      <div class=\"time-badge\">⏱ 1200+ Unterrichtsstunden (ab Null)</div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ SELF-ASSESSMENT ════════════════════ -->\n  <div class=\"section-header\"><h2>Wie Sie Ihr Niveau einschätzen</h2></div>\n\n  <p style=\"color:var(--muted); margin-bottom:24px; font-size:0.96rem; line-height:1.75;\">\n    Bewerten Sie sich <strong style=\"color:var(--text)\">getrennt in vier Kompetenzbereichen</strong>. Ihr tatsächliches Sprachniveau entspricht dem Bereich, in dem Sie in mindestens 3 von 4 Fertigkeiten stabil und zuverlässig agieren können. Oft hinkt eine Fertigkeit hinter den anderen her – das ist völlig normal und zeigt, wo gezieltes Üben am sinnvollsten ist.\n  </p>\n\n  <div class=\"assessment-grid\">\n    <div class=\"ag-cell\">\n      <div class=\"ag-icon\">🎧</div>\n      <div class=\"ag-label\">Hören</div>\n      <div class=\"ag-desc\">Verstehen Sie gesprochene Sprache, Nachrichten, Podcasts und Filme?</div>\n    </div>\n    <div class=\"ag-cell\">\n      <div class=\"ag-icon\">📖</div>\n      <div class=\"ag-label\">Lesen</div>\n      <div class=\"ag-desc\">Verstehen Sie Briefe, Artikel, Verträge und Anleitungen?</div>\n    </div>\n    <div class=\"ag-cell\">\n      <div class=\"ag-icon\">🗣</div>\n      <div class=\"ag-label\">Sprechen</div>\n      <div class=\"ag-desc\">Können Sie spontan reagieren, erzählen und argumentieren?</div>\n    </div>\n    <div class=\"ag-cell\">\n      <div class=\"ag-icon\">✍️</div>\n      <div class=\"ag-label\">Schreiben</div>\n      <div class=\"ag-desc\">Können Sie klare, korrekte und situationsgerechte Texte verfassen?</div>\n    </div>\n  </div>\n\n  <!-- ════════════════════ PRÜFUNGEN ════════════════════ -->\n  <div class=\"section-header\"><h2>Offizielle Prüfungen und Zertifikate</h2></div>\n\n  <p style=\"color:var(--muted); margin-bottom:20px; font-size:0.95rem; line-height:1.75;\">\n    Die folgende Tabelle zeigt die wichtigsten anerkannten Deutschzertifikate und ihren praktischen Nutzen. Alle genannten Prüfungen werden international anerkannt – insbesondere für Behörden, Universitäten und Arbeitgeber im deutschsprachigen Raum.\n  </p>\n\n  <table class=\"exams-table\">\n    <thead>\n      <tr>\n        <th>Niveau</th>\n        <th>Goethe-Institut</th>\n        <th>ÖSD (Österreich)</th>\n        <th>telc</th>\n        <th>Wozu wird es benötigt?</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td><strong style=\"color:var(--a1)\">A1</strong></td>\n        <td>Goethe-Zertifikat A1</td>\n        <td>ÖSD Zertifikat A1</td>\n        <td>telc Deutsch A1</td>\n        <td>Familienzusammenführung (DE / AT), Einreisevisum</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--a2)\">A2</strong></td>\n        <td>Goethe-Zertifikat A2</td>\n        <td>ÖSD Zertifikat A2</td>\n        <td>telc Deutsch A2</td>\n        <td>Grundlegende Sozialleistungen, manche Ausbildungsplätze</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--b1)\">B1</strong></td>\n        <td>Goethe-Zertifikat B1</td>\n        <td>ÖSD Zertifikat B1</td>\n        <td>telc Deutsch B1</td>\n        <td>Niederlassungsbewilligung (AT / DE), Einbürgerung (CH), viele Berufsausbildungen</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--b2)\">B2</strong></td>\n        <td>Goethe-Zertifikat B2</td>\n        <td>ÖSD Zertifikat B2</td>\n        <td>telc Deutsch B2</td>\n        <td>Hochschulzulassung (AT / DE), medizinische Berufsanerkennung (Ärzte, Pflege, Apotheke)</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--c1)\">C1</strong></td>\n        <td>Goethe-Zertifikat C1</td>\n        <td>ÖSD Zertifikat C1</td>\n        <td>telc Deutsch C1 Hochschule</td>\n        <td>Akademische Karriere, Führungspositionen, MasterStudium ohne Deutschkurs</td>\n      </tr>\n      <tr>\n        <td><strong style=\"color:var(--c2)\">C2</strong></td>\n        <td>Goethe-Zertifikat C2 (GDS)</td>\n        <td>ÖSD Zertifikat C2</td>\n        <td>—</td>\n        <td>Unterrichten, Übersetzen, Dolmetschen, Top-Management, Journalismus auf Muttersprachniveau</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- ════════════════════ LERNTIPPS ════════════════════ -->\n  <div class=\"section-header\"><h2>Tipps für effektives Lernen</h2></div>\n\n  <div class=\"tips-grid\">\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">🎯</div>\n      <div class=\"tip-title\">Täglich lernen – auch nur 15 Minuten</div>\n      <div class=\"tip-desc\">Regelmäßigkeit schlägt Intensität: 15 Minuten täglich sind wirksamer als 3 Stunden einmal pro Woche. Unser Gehirn festigt Sprache im Schlaf und durch Wiederholung.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">📻</div>\n      <div class=\"tip-title\">Echte Sprache hören</div>\n      <div class=\"tip-desc\">Ab A2 regelmäßig Podcasts, „Slow German\", Deutsche Welle oder Radionachrichten hören. Das schult das Hörverständnis für echte Sprechsituationen – nicht nur für den Unterricht.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">📝</div>\n      <div class=\"tip-title\">Vokabelheft mit Kontext führen</div>\n      <div class=\"tip-desc\">Neue Wörter immer im ganzen Satz aufschreiben, nicht isoliert. Gehirn speichert Wörter in Bedeutungsnetzwerken – Kontext ist der Schlüssel zur langfristigen Erinnerung.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">💬</div>\n      <div class=\"tip-title\">Vom ersten Tag an sprechen</div>\n      <div class=\"tip-desc\">Warten Sie nicht auf das „richtige Niveau\". Fehler sind kein Zeichen von Schwäche – sie sind Lernmaterial. Nur wer spricht, lernt wirklich sprechen. Mut zahlt sich aus.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">🎮</div>\n      <div class=\"tip-title\">Im Kontext eintauchen</div>\n      <div class=\"tip-desc\">Serien mit deutschen Untertiteln schauen, auf Deutsch spielen, Bücher lesen – alles ist Sprachkontakt. Je natürlicher der Kontext, desto tiefer verankert sich die Sprache.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">🗂</div>\n      <div class=\"tip-title\">Ein Niveau – ein Fokus</div>\n      <div class=\"tip-desc\">Mischen Sie keine C1-Grammatik in einen A2-Kurs. Das verursacht Verwirrung und verlangsamt den Fortschritt. Wer sein Niveau kennt, lernt gezielt und effizient.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">🔁</div>\n      <div class=\"tip-title\">Wiederholen mit System (Spaced Repetition)</div>\n      <div class=\"tip-desc\">Nutzen Sie Apps wie Anki oder Quizlet für systematische Wiederholung. Das Spaced-Repetition-Prinzip ist wissenschaftlich belegt als effizienteste Methode für Vokabellernen.</div>\n    </div>\n    <div class=\"tip-card\">\n      <div class=\"tip-icon\">🧑‍🤝‍🧑</div>\n      <div class=\"tip-title\">Tandempartner suchen</div>\n      <div class=\"tip-desc\">Ein Sprachpartner, der Deutsch als Muttersprache spricht und Ihre Sprache lernen möchte, ist unbezahlbar. Plattformen wie Tandem, HelloTalk oder lokale Sprachcafés helfen.</div>\n    </div>\n  </div>\n\n  <div class=\"notice\" style=\"margin-top:4px;\">\n    <strong>Hinweis zu den Stundenzahlen:</strong> Die angegebenen Stunden sind Richtwerte des Europarates und des Goethe-Instituts. Die tatsächlich benötigte Zeit hängt von der Muttersprache ab (slawische Sprachen liegen näher am Deutschen als romanische oder türkische), von der Unterrichtsintensität, der Lernerfahrung und dem sprachlichen Umfeld. Wer in einem deutschsprachigen Land lebt, macht in der Regel deutlich schneller Fortschritte als jemand, der nur im Klassenraum lernt.\n  </div>\n\n</div>\n\n<!-- ════════════════════ FOOTER ════════════════════ -->\n<footer>\n  <p>Quellen: <a href=\"https://www.coe.int/en/web/common-european-framework-reference-languages\" target=\"_blank\">Europarat – GER/CEFR</a> · <a href=\"https://www.goethe.de\" target=\"_blank\">Goethe-Institut</a> · <a href=\"https://www.osd.at\" target=\"_blank\">ÖSD</a> · <a href=\"https://www.telc.net\" target=\"_blank\">telc GmbH</a></p>\n  <p style=\"margin-top:6px;\">Lernplan aktualisiert 2025 · Für Unterrichtszwecke</p>\n</footer>\n\n<script>\n  function toggleCard(id) {\n    const card = document.getElementById(id);\n    card.classList.toggle('open');\n  }\n  document.getElementById('lv-a1').classList.add('open');\n</script>\n\n",
    "styles": "\n  .dq-article-document {\n    --bg: #0f0f13;\n    --surface: #17171e;\n    --border: #2a2a38;\n    --text: #e8e6f0;\n    --muted: #8a8aa0;\n    --accent: #f0c040;\n\n    --a0: #9b9b9b;\n    --a1: #6ec6e0;\n    --a2: #4db8a8;\n    --b1: #7ec86e;\n    --b2: #c8b84e;\n    --c1: #e07848;\n    --c2: #d04870;\n\n    --a0-bg: rgba(155,155,155,0.08);\n    --a1-bg: rgba(110,198,224,0.08);\n    --a2-bg: rgba(77,184,168,0.08);\n    --b1-bg: rgba(126,200,110,0.08);\n    --b2-bg: rgba(200,184,78,0.08);\n    --c1-bg: rgba(224,120,72,0.08);\n    --c2-bg: rgba(208,72,112,0.08);\n  }\n\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n  .dq-article-document {\n    background: var(--bg);\n    color: var(--text);\n    font-family: 'Source Sans 3', sans-serif;\n    font-weight: 300;\n    line-height: 1.75;\n    min-height: 100vh;\n  }\n\n  /* ── HERO ── */\n  .hero {\n    position: relative;\n    padding: 88px 24px 64px;\n    text-align: center;\n    overflow: hidden;\n  }\n  .hero::before {\n    content: '';\n    position: absolute;\n    inset: 0;\n    background:\n      radial-gradient(ellipse 80% 60% at 50% 0%, rgba(240,192,64,0.13) 0%, transparent 70%),\n      radial-gradient(ellipse 50% 40% at 80% 80%, rgba(208,72,112,0.09) 0%, transparent 60%);\n    pointer-events: none;\n  }\n  .hero-eyebrow {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 12px;\n    letter-spacing: 0.22em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 18px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.1s forwards;\n  }\n  .hero h1 {\n    font-family: 'Playfair Display', serif;\n    font-size: clamp(2.4rem, 6vw, 4.8rem);\n    font-weight: 900;\n    line-height: 1.1;\n    margin-bottom: 22px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.25s forwards;\n  }\n  .hero h1 em { font-style: normal; color: var(--accent); }\n  .hero-sub {\n    max-width: 660px;\n    margin: 0 auto 44px;\n    color: var(--muted);\n    font-size: 1.08rem;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.4s forwards;\n  }\n\n  /* ── LEVEL STRIP ── */\n  .level-strip {\n    display: flex;\n    justify-content: center;\n    flex-wrap: wrap;\n    gap: 7px;\n    margin-bottom: 10px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.55s forwards;\n  }\n  .level-pill {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 13px;\n    font-weight: 600;\n    padding: 5px 16px;\n    border-radius: 20px;\n    border: 1.5px solid currentColor;\n  }\n  .pill-a0 { color: var(--a0); }\n  .pill-a1 { color: var(--a1); }\n  .pill-a2 { color: var(--a2); }\n  .pill-b1 { color: var(--b1); }\n  .pill-b2 { color: var(--b2); }\n  .pill-c1 { color: var(--c1); }\n  .pill-c2 { color: var(--c2); }\n\n  .group-label {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.18em;\n    color: var(--muted);\n    text-align: center;\n    margin-bottom: 36px;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.65s forwards;\n  }\n\n  /* ── CEFR SUMMARY BAR ── */\n  .cefr-bar {\n    max-width: 860px;\n    margin: 0 auto 0;\n    display: grid;\n    grid-template-columns: 1fr 1fr 1fr;\n    border: 1px solid var(--border);\n    border-radius: 14px;\n    overflow: hidden;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.75s forwards;\n  }\n  @media (max-width: 600px) { .cefr-bar { grid-template-columns: 1fr; } }\n  .cefr-group {\n    padding: 22px 26px;\n    border-right: 1px solid var(--border);\n    text-align: center;\n  }\n  .cefr-group:last-child { border-right: none; }\n  .cefr-group-label {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.15em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 7px;\n  }\n  .cefr-group-title {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.12rem;\n    font-weight: 700;\n    margin-bottom: 5px;\n  }\n  .cefr-group-sub { font-size: 0.82rem; color: var(--muted); }\n  .cefr-group.elementary .cefr-group-title { color: var(--a1); }\n  .cefr-group.independent .cefr-group-title { color: var(--b1); }\n  .cefr-group.proficient .cefr-group-title { color: var(--c1); }\n\n  /* ── MAIN CONTAINER ── */\n  .container {\n    max-width: 900px;\n    margin: 0 auto;\n    padding: 0 24px 88px;\n  }\n\n  /* ── SECTION HEADER ── */\n  .section-header {\n    display: flex;\n    align-items: center;\n    gap: 16px;\n    margin: 60px 0 32px;\n  }\n  .section-header::after {\n    content: '';\n    flex: 1;\n    height: 1px;\n    background: var(--border);\n  }\n  .section-header h2 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    letter-spacing: 0.2em;\n    text-transform: uppercase;\n    color: var(--muted);\n    white-space: nowrap;\n  }\n\n  /* ── LEVEL CARD ── */\n  .level-card {\n    border: 1px solid var(--border);\n    border-radius: 16px;\n    overflow: hidden;\n    margin-bottom: 28px;\n    opacity: 0;\n    animation: fadeUp 0.5s ease forwards;\n    transition: border-color 0.25s;\n  }\n  .level-card:nth-child(1) { animation-delay: 0.05s; }\n  .level-card:nth-child(2) { animation-delay: 0.12s; }\n  .level-card:nth-child(3) { animation-delay: 0.19s; }\n  .level-card:nth-child(4) { animation-delay: 0.26s; }\n  .level-card:nth-child(5) { animation-delay: 0.33s; }\n  .level-card:nth-child(6) { animation-delay: 0.40s; }\n  .level-card:nth-child(7) { animation-delay: 0.47s; }\n\n  .card-header {\n    display: grid;\n    grid-template-columns: auto 1fr auto;\n    align-items: center;\n    gap: 20px;\n    padding: 26px 30px 22px;\n    cursor: pointer;\n    user-select: none;\n  }\n  .level-badge {\n    font-family: 'Playfair Display', serif;\n    font-size: 2.4rem;\n    font-weight: 900;\n    line-height: 1;\n    width: 68px;\n    text-align: center;\n  }\n  .card-title {\n    font-family: 'Playfair Display', serif;\n    font-size: 1.35rem;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 5px;\n  }\n  .card-subtitle { font-size: 0.86rem; color: var(--muted); }\n  .card-toggle {\n    font-size: 22px;\n    color: var(--muted);\n    transition: transform 0.3s;\n    line-height: 1;\n  }\n  .level-card.open .card-toggle { transform: rotate(180deg); }\n\n  .card-.dq-article-document {\n    padding: 0 30px;\n    max-height: 0;\n    overflow: hidden;\n    transition: max-height 0.5s ease, padding 0.3s ease;\n  }\n  .level-card.open .card-.dq-article-document {\n    max-height: 3000px;\n    padding-bottom: 30px;\n  }\n\n  /* ── DESCRIPTION PARAGRAPH ── */\n  .card-description {\n    font-size: 0.97rem;\n    color: var(--muted);\n    margin-bottom: 24px;\n    line-height: 1.8;\n    padding: 16px 20px;\n    background: rgba(255,255,255,0.025);\n    border-radius: 10px;\n    border-left: 3px solid currentColor;\n  }\n\n  .card-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 20px;\n    margin-bottom: 20px;\n  }\n  @media (max-width: 640px) {\n    .card-grid { grid-template-columns: 1fr; }\n    .card-header { gap: 12px; padding: 20px 20px 18px; }\n    .card-.dq-article-document { padding: 0 20px; }\n    .level-card.open .card-.dq-article-document { padding-bottom: 20px; }\n  }\n\n  .card-block {\n    background: var(--surface);\n    border-radius: 10px;\n    padding: 18px 20px;\n  }\n  .card-block h4 {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--muted);\n    margin-bottom: 13px;\n  }\n  .card-block ul {\n    list-style: none;\n    display: flex;\n    flex-direction: column;\n    gap: 8px;\n  }\n  .card-block ul li {\n    font-size: 0.91rem;\n    padding-left: 20px;\n    position: relative;\n    color: var(--text);\n    line-height: 1.6;\n  }\n  .card-block ul li::before {\n    content: '→';\n    position: absolute;\n    left: 0;\n    font-size: 0.75rem;\n    top: 2px;\n  }\n  .card-block-full { grid-column: 1 / -1; }\n\n  .grammar-tags {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n  }\n  .grammar-tag {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    padding: 4px 11px;\n    border-radius: 6px;\n    background: rgba(255,255,255,0.05);\n    border: 1px solid var(--border);\n    color: var(--muted);\n  }\n\n  .example-item {\n    font-family: 'Playfair Display', serif;\n    font-size: 0.97rem;\n    font-style: italic;\n    color: var(--text);\n    padding: 9px 15px;\n    border-left: 2.5px solid currentColor;\n    margin-bottom: 9px;\n    background: rgba(255,255,255,0.025);\n    border-radius: 0 7px 7px 0;\n    line-height: 1.6;\n  }\n  .example-item .translation {\n    display: block;\n    font-family: 'Source Sans 3', sans-serif;\n    font-style: normal;\n    font-size: 0.8rem;\n    color: var(--muted);\n    margin-top: 3px;\n  }\n\n  .selftest-item {\n    display: flex;\n    align-items: flex-start;\n    gap: 10px;\n    font-size: 0.91rem;\n    margin-bottom: 9px;\n    line-height: 1.6;\n  }\n  .selftest-check {\n    width: 20px;\n    height: 20px;\n    border: 1.5px solid var(--border);\n    border-radius: 5px;\n    flex-shrink: 0;\n    margin-top: 2px;\n  }\n\n  .time-badge {\n    display: inline-flex;\n    align-items: center;\n    gap: 7px;\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 11px;\n    color: var(--muted);\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 7px;\n    padding: 5px 12px;\n    margin-top: 14px;\n  }\n\n  /* ── LEVEL COLORS ── */\n  .lv-a0 { color: var(--a0); border-color: rgba(155,155,155,0.2); }\n  .lv-a1 { color: var(--a1); border-color: rgba(110,198,224,0.2); }\n  .lv-a2 { color: var(--a2); border-color: rgba(77,184,168,0.2); }\n  .lv-b1 { color: var(--b1); border-color: rgba(126,200,110,0.2); }\n  .lv-b2 { color: var(--b2); border-color: rgba(200,184,78,0.2); }\n  .lv-c1 { color: var(--c1); border-color: rgba(224,120,72,0.2); }\n  .lv-c2 { color: var(--c2); border-color: rgba(208,72,112,0.2); }\n\n  .level-card.lv-a0:hover { border-color: var(--a0); }\n  .level-card.lv-a1:hover { border-color: var(--a1); }\n  .level-card.lv-a2:hover { border-color: var(--a2); }\n  .level-card.lv-b1:hover { border-color: var(--b1); }\n  .level-card.lv-b2:hover { border-color: var(--b2); }\n  .level-card.lv-c1:hover { border-color: var(--c1); }\n  .level-card.lv-c2:hover { border-color: var(--c2); }\n\n  .example-item.lv-a0 { border-color: var(--a0); }\n  .example-item.lv-a1 { border-color: var(--a1); }\n  .example-item.lv-a2 { border-color: var(--a2); }\n  .example-item.lv-b1 { border-color: var(--b1); }\n  .example-item.lv-b2 { border-color: var(--b2); }\n  .example-item.lv-c1 { border-color: var(--c1); }\n  .example-item.lv-c2 { border-color: var(--c2); }\n\n  .card-description.lv-a0 { border-color: var(--a0); }\n  .card-description.lv-a1 { border-color: var(--a1); }\n  .card-description.lv-a2 { border-color: var(--a2); }\n  .card-description.lv-b1 { border-color: var(--b1); }\n  .card-description.lv-b2 { border-color: var(--b2); }\n  .card-description.lv-c1 { border-color: var(--c1); }\n  .card-description.lv-c2 { border-color: var(--c2); }\n\n  /* ── PROGRESS BAR ── */\n  .progress-track {\n    max-width: 860px;\n    margin: 0 auto 68px;\n    padding: 28px 24px 0;\n    opacity: 0;\n    animation: fadeUp 0.6s ease 0.85s forwards;\n  }\n  .progress-bar {\n    display: flex;\n    height: 8px;\n    border-radius: 4px;\n    overflow: hidden;\n    margin-bottom: 10px;\n  }\n  .pb-seg { height: 100%; }\n  .pb-a0 { flex: 1; background: var(--a0); }\n  .pb-a1 { flex: 1.2; background: var(--a1); }\n  .pb-a2 { flex: 1.4; background: var(--a2); }\n  .pb-b1 { flex: 1.6; background: var(--b1); }\n  .pb-b2 { flex: 1.8; background: var(--b2); }\n  .pb-c1 { flex: 2; background: var(--c1); }\n  .pb-c2 { flex: 2.2; background: var(--c2); }\n  .progress-labels {\n    display: flex;\n    justify-content: space-between;\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    color: var(--muted);\n  }\n\n  /* ── ASSESSMENT GRID ── */\n  .assessment-grid {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 1px;\n    background: var(--border);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    overflow: hidden;\n    margin-bottom: 28px;\n  }\n  @media (max-width: 600px) { .assessment-grid { grid-template-columns: 1fr 1fr; } }\n  .ag-cell {\n    background: var(--surface);\n    padding: 22px 16px;\n    text-align: center;\n  }\n  .ag-icon { font-size: 30px; margin-bottom: 10px; }\n  .ag-label {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.15em;\n    text-transform: uppercase;\n    color: var(--accent);\n    margin-bottom: 7px;\n  }\n  .ag-desc { font-size: 0.83rem; color: var(--muted); line-height: 1.5; }\n\n  /* ── EXAMS TABLE ── */\n  .exams-table {\n    width: 100%;\n    border-collapse: collapse;\n    margin-bottom: 28px;\n    font-size: 0.88rem;\n  }\n  .exams-table th {\n    font-family: 'JetBrains Mono', monospace;\n    font-size: 10px;\n    letter-spacing: 0.15em;\n    text-transform: uppercase;\n    color: var(--muted);\n    text-align: left;\n    padding: 13px 16px;\n    border-bottom: 1px solid var(--border);\n    background: var(--surface);\n  }\n  .exams-table td {\n    padding: 13px 16px;\n    border-bottom: 1px solid var(--border);\n    vertical-align: top;\n    line-height: 1.5;\n  }\n  .exams-table tr:last-child td { border-bottom: none; }\n  .exams-table tr:hover td { background: rgba(255,255,255,0.02); }\n\n  /* ── TIPS GRID ── */\n  .tips-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 16px;\n    margin-bottom: 28px;\n  }\n  @media (max-width: 600px) { .tips-grid { grid-template-columns: 1fr; } }\n  .tip-card {\n    background: var(--surface);\n    border: 1px solid var(--border);\n    border-radius: 12px;\n    padding: 22px;\n  }\n  .tip-icon { font-size: 26px; margin-bottom: 12px; }\n  .tip-title {\n    font-family: 'Source Sans 3', sans-serif;\n    font-weight: 600;\n    font-size: 0.97rem;\n    margin-bottom: 7px;\n  }\n  .tip-desc { font-size: 0.86rem; color: var(--muted); line-height: 1.65; }\n\n  /* ── NOTICE BOX ── */\n  .notice {\n    background: rgba(240,192,64,0.07);\n    border: 1px solid rgba(240,192,64,0.2);\n    border-radius: 10px;\n    padding: 18px 22px;\n    font-size: 0.89rem;\n    color: var(--muted);\n    margin-bottom: 28px;\n    line-height: 1.7;\n  }\n  .notice strong { color: var(--accent); }\n\n  /* ── FOOTER ── */\n  footer {\n    border-top: 1px solid var(--border);\n    padding: 36px 24px;\n    text-align: center;\n    color: var(--muted);\n    font-size: 0.83rem;\n    line-height: 1.8;\n  }\n  footer a { color: var(--accent); text-decoration: none; }\n  footer a:hover { text-decoration: underline; }\n\n  /* ── ANIMATIONS ── */\n  @keyframes fadeUp {\n    from { opacity: 0; transform: translateY(18px); }\n    to   { opacity: 1; transform: translateY(0); }\n  }\n"
  }
};